window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q04"]=window.__LIBQ["pham-nhan-tu-tien"]["q04"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q04"]["factions"]={"updatedAt":"2026-07-13","count":65,"factions":[{"id":"khoi-tinh-dao","name":"Khôi Tinh Đảo","cn":"","type":"dao-cu-tru","typeLabel":"Đảo cư trú","diaBan":"vùng tây nam Loạn Tinh Hải","nhanVatChinh":["Cố đông chủ"],"blurb":"Khôi Tinh Đảo là một trong ba đảo lớn phụ cận vùng tây nam Loạn Tinh Hải. Cố đông chủ muốn mời Hàn Lập đến nơi này cư trú và hứa cung ứng chi phí tu hành, sinh hoạt.","detail":"Theo lời Vương Trường Thanh, Khôi Tinh Đảo cùng Vĩ Tinh đảo và Tang Tinh là ba hòn đảo lớn phụ cận hải vực hiện tại. Đảo có liên hệ với Cố đông chủ, người mời Hàn Lập tới ở lại sau khi gặp hắn trên hải thuyền.","trangThai":"đang tồn tại","quanHe":"Một trong ba đảo lớn phụ cận tây nam Loạn Tinh Hải.","thanhVien":[{"ten":"Cố đông chủ","chucVu":"người liên hệ từ hải thuyền","tuChuong":"@c0365","trangThai":"đang hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0365","loai":"nhắc tới","importance":"normal","giaiDoan":"Được mời đến cư trú","text":"Khôi Tinh Đảo được Cố đông chủ nêu làm nơi muốn mời Hàn Lập đến ở, đồng thời được Vương Trường Thanh xếp vào ba đảo lớn phụ cận.","anchor":"Phụ cận gồm có Vĩ Tinh đảo, Khôi Tinh đảo cùng Tang Tinh là ba hòn đảo lớn"}]},"capNhatToi":"@c0365","nguon":["@c0365"]},{"id":"quy-che-dao-chu-loan-tinh-hai","name":"Quy chế đảo chủ Loạn Tinh Hải","cn":"","type":"che-do-quan-tri","typeLabel":"Chế độ quản trị đảo","diaBan":"các đảo tại Loạn Tinh Hải","nhanVatChinh":[],"blurb":"Quy chế đảo chủ Loạn Tinh Hải là cách các đảo do tiên sư pháp lực cao nhất đứng đầu và quản lý tu sĩ cư trú. Tu sĩ nhận chức được cấp linh thạch hằng năm nhưng phải nghe điều động, còn tu sĩ chỉ ở lại thì phải nộp linh thạch cho đảo chủ.","detail":"Vương Trường Thanh giải thích rằng mỗi đảo đều có một tiên sư pháp lực cao nhất làm đảo chủ. Dưới quy chế này, tu sĩ đảm nhiệm chức vụ trên đảo được nhận linh thạch hằng năm nhưng chịu sự phân phó của đảo chủ, trong khi tu sĩ không nhận chức phải nộp linh thạch hằng năm để được cư trú.","nguonGoc":"tập tục vận hành các đảo tại Loạn Tinh Hải","lanhDaoHienThoi":"đảo chủ từng đảo","trangThai":"đang vận hành","quanHe":"Chi phối việc tu sĩ nhận chức hoặc cư trú trên các đảo.","tabs":{"tienTrinh":[{"chuong":"@c0365","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Vương Trường Thanh giải thích","text":"Quy chế đảo chủ được giới thiệu như nền tảng quản lý tu sĩ trên các đảo, gắn quyền cư trú và chức vụ với việc cấp hoặc nộp linh thạch.","anchor":"mỗi một đảo cũng đều có một tiên sư pháp lực cao nhất làm đảo chủ"}]},"capNhatToi":"@c0365","nguon":["@c0365"]},{"id":"co-gia","name":"Cố gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc buôn bán","diaBan":"Tuyến hải thuyền đến Khôi Tinh Đảo","nhanVatChinh":["Cố đông chủ","Vương Trường Thanh","Hàn Lập"],"blurb":"Gia tộc buôn bán của Cố đông chủ đang đặt cược lớn vào việc tranh tư cách giao dịch giữa các đại đảo.","detail":"Cố gia đã tiêu tốn nhiều cho hải thuyền và tư cách khiêu chiến. Nếu không giành được tư cách buôn bán giữa các đại đảo, gia tộc có nguy cơ phá sản, nên Cố đông chủ dùng linh thạch, bảo nhân định cư và lợi nhuận ba năm để mời Hàn Lập trợ giúp.","trangThai":"nguy cơ phá sản nếu thất bại","thanhVien":[{"ten":"Cố đông chủ","chucVu":"chủ sự","tuChuong":"@c0367","trangThai":"đang điều hành việc mời trợ giúp"},{"ten":"Vương Trường Thanh","chucVu":"người giải thích và thuyết phục","tuChuong":"@c0367","trangThai":"hỗ trợ Cố đông chủ"}],"tabs":{"tienTrinh":[{"chuong":"@c0367","loai":"nhắc tới","importance":"normal","giaiDoan":"Tranh tư cách buôn bán","trangThaiMoc":"nguy cơ phá sản","text":"Cố gia phải mời Hàn Lập trợ giúp vì việc giành tư cách buôn bán giữa các đại đảo liên quan trực tiếp đến nguy cơ phá sản.","anchor":"Nếu không có được tư cách buôn bán giữa các đại đảo, Cố gia nhất định sẽ phá sản"}]},"capNhatToi":"@c0367","nguon":["@c0367"]},{"id":"muoi-thuong-gia","name":"Mười thương gia","cn":"","type":"nhom-thuong-gia","typeLabel":"Nhóm thương gia","diaBan":"Khôi Tinh Đảo","nhanVatChinh":["Cố đông chủ"],"blurb":"Mười thương gia là nhóm có đại diện bị khiêu chiến trong ngày mở cửa của Khôi Tinh Đảo. Người thắng vòng rút thẻ mới được trao tư cách khiêu chiến đại diện của họ.","detail":"Trong vòng đấu loại tại cung điện trung tâm, các tu sĩ khiêu chiến phải đấu với nhau trước để giành quyền khiêu chiến đại diện của mười thương gia. Cố gia là một trong các nhà liên quan tới vòng khiêu chiến này.","trangThai":"đang tổ chức vòng khiêu chiến","capNhatToi":"@c0369","thanhVien":[{"ten":"Cố đông chủ","chucVu":"Đại diện Cố gia","tuChuong":"@c0369","trangThai":"tham gia đưa người khiêu chiến"}],"tabs":{"tienTrinh":[{"chuong":"@c0369","loai":"nhắc tới","importance":"normal","giaiDoan":"Vòng đấu loại khiêu chiến","trangThaiMoc":"Đại diện mười thương gia chờ người thắng vòng rút thẻ tới khiêu chiến","text":"Vòng đấu loại được tổ chức để chọn người thắng đủ tư cách khiêu chiến đại diện của mười thương gia.","anchor":"người thắng mới có tư cách khiêu chiến đại diện của mười thương gia kia"}]},"nguon":["@c0369"]},{"id":"ho-ve-doi-khoi-tinh-dao","name":"Hộ vệ đội Khôi Tinh Đảo","cn":"","type":"doi-nhom","typeLabel":"Đội hộ vệ thuê","diaBan":"Khôi Tinh Đảo","nhanVatChinh":["Đệ tử bất tài của trung niên nhân phụ trách Đăng Tiên Các"],"blurb":"Hộ vệ đội Khôi Tinh Đảo là nhóm đả thủ do các đại hộ thuê lập thành. Dù tu vi không cao, họ thường ra biển săn yêu thú và đấu pháp nên có kinh nghiệm chiến đấu hơn tu sĩ thường.","detail":"Văn Tường giải thích với Hàn Lập rằng mười tu sĩ bị khiêu chiến vốn thuộc nhóm đả thủ nhàn rỗi do các đại hộ thuê để lập thành hộ vệ đội trên đảo. Họ thường xuyên xuất hải săn yêu thú nên thủ đoạn và kinh nghiệm chiến đấu đáng kể.","nguonGoc":"Do các đại hộ thuê đả thủ nhàn rỗi lập thành trên Khôi Tinh Đảo.","thanhVien":[{"ten":"Đệ tử bất tài của trung niên nhân phụ trách Đăng Tiên Các","chucVu":"thành viên hộ vệ đội","tuChuong":"@c0371","trangThai":"đang thuộc đội"}],"congNang":["Bảo vệ và tham gia các việc đấu pháp, săn yêu thú trên đảo @c0371"],"tabs":{"tienTrinh":[{"chuong":"@c0371","loai":"nhắc tới","importance":"normal","giaiDoan":"Lý lịch hộ vệ đội","text":"Văn Tường cho biết nhóm hộ vệ do các đại hộ thuê đả thủ lập thành, thường ra biển săn yêu thú nên kinh nghiệm chiến đấu vượt tu sĩ thường.","anchor":"đều là do những đại hộ thuê những mấy đả thủ nhàn rỗi tới bổn đảo lập thành hộ vệ đội"}]},"capNhatToi":"@c0371","nguon":["@c0371"]},{"id":"cu-dan-tieu-hoan-dao","name":"Cư dân Tiểu Hoàn Đảo","cn":"","aliases":[],"type":"cong-dong","typeLabel":"Cộng đồng dân cư","diaBan":"Tiểu Hoàn Đảo","nhanVatChinh":["Hắc Quý","Nhóm ngư dân Tiểu Hoàn Đảo"],"blurb":"Cộng đồng phàm nhân sinh sống trên Tiểu Hoàn Đảo, có một trấn nhỏ khoảng vài trăm nhân khẩu. Họ liên quan trực tiếp đến nghĩa vụ duy trì trận pháp phòng hộ của đảo.","detail":"Cư dân Tiểu Hoàn Đảo có thể bồi thường linh thạch ở mức nhất định nhưng không đủ bù hao tổn thường ngày của phòng hộ trận. Khi Hàn Lập đến đảo, nhóm ngư dân đại diện tiếp xúc với hắn tại bến tàu.","quyMo":"khoảng vài trăm nhân khẩu","trangThai":"sinh sống trên Tiểu Hoàn Đảo","thanhVien":[{"ten":"Hắc Quý","chucVu":"người đại diện nhóm ngư dân","tuChuong":"@c0372","trangThai":"còn thuộc"},{"ten":"Nhóm ngư dân Tiểu Hoàn Đảo","chucVu":"cư dân tại bến tàu","tuChuong":"@c0372","trangThai":"còn thuộc"}],"tabs":{"tienTrinh":[{"chuong":"@c0372","loai":"nhắc tới","importance":"normal","giaiDoan":"được giới thiệu quy mô","trangThaiMoc":"đang sinh sống trên đảo","text":"Cư dân Tiểu Hoàn Đảo được giới thiệu là một trấn nhỏ vài trăm nhân khẩu, không đủ bù hao tổn duy trì phòng hộ trận.","anchor":"Đã kiến tạo một cái trấn nhỏ trên đảo ước chừng cũng được mấy trăm nhân khẩu"}]},"capNhatToi":"@c0372","nguon":["@c0372"]},{"id":"dang-tien-cac-faction","name":"Đăng Tiên Các","cn":"","type":"to-chuc","typeLabel":"Tổ chức tu sĩ giao dịch","diaBan":"Khôi Tinh Đảo","nhanVatChinh":["Trung niên tu sĩ Đăng Tiên Các","Đồ đệ của trung niên tu sĩ Đăng Tiên Các"],"blurb":"Đăng Tiên Các liên quan đến mâu thuẫn giữa trung niên tu sĩ và Hàn Lập về tư cách kinh doanh trên đảo. Chương này đồ đệ của trung niên tu sĩ thuộc Đăng Tiên Các đến Tiểu Hoàn Đảo khiêu chiến Hàn Lập.","detail":"Đăng Tiên Các là nơi gắn với trung niên tu sĩ từng có xung đột lợi ích cùng Hàn Lập. Khi Hàn Lập bế quan tu Đại Diễn Quyết, đồ đệ của người này phụng lệnh đến Tiểu Hoàn Đảo khiêu chiến nhưng bị đại trận và Hàn Lập đánh bại.","thanhVien":[{"ten":"Trung niên tu sĩ Đăng Tiên Các","chucVu":"tu sĩ liên quan Đăng Tiên Các","tuChuong":"@c0374","trangThai":"đang hoạt động"},{"ten":"Đồ đệ của trung niên tu sĩ Đăng Tiên Các","chucVu":"đồ đệ","tuChuong":"@c0374","trangThai":"bị Hàn Lập đánh bại"}],"tabs":{"tienTrinh":[{"chuong":"@c0374","loai":"nhắc tới","importance":"normal","giaiDoan":"Khiêu chiến Tiểu Hoàn Đảo","text":"Đồ đệ của trung niên tu sĩ Đăng Tiên Các phụng lệnh đến Tiểu Hoàn Đảo khiêu chiến Hàn Lập và thất bại.","anchor":"đành phụng theo mệnh lênh của trung niên tu sĩ lại đến Tiểu Hoàn Đảo"}]},"nguon":["@c0374"]},{"id":"cu-dan-tran-tieu-hoan-dao","name":"Cư dân trấn Tiểu Hoàn Đảo","cn":"","aliases":["Cư dân Tiểu Hoàn Đảo","Trấn Tiểu Hoàn Đảo"],"type":"cong-dong","typeLabel":"Cộng đồng phàm nhân","diaBan":"Tiểu Hoàn Đảo","nhanVatChinh":["Hắc Quý","Dân cư Tiểu Hoàn Đảo"],"blurb":"Cư dân trấn Tiểu Hoàn Đảo là cộng đồng phàm nhân sống gần động phủ Hàn Lập. Họ tiếp tục đánh cá, tránh bạch vụ quanh hai ngọn núi và hằng năm nhận linh thạch duy trì trận pháp.","detail":"Sau hơn hai mươi năm Hàn Lập bế quan, cư dân trên đảo đã quen với việc hai ngọn núi bị bạch vụ che phủ. Trưởng trấn mới Hắc Quý theo lệ đứng ngoài bạch vụ gọi Hàn tiên sư để nhận linh thạch duy trì trận pháp phòng hộ thôn trấn.","thanhVien":[{"ten":"Hắc Quý","chucVu":"trưởng trấn mới","tuChuong":"@c0374","trangThai":"đang tại chức"},{"ten":"Dân cư Tiểu Hoàn Đảo","chucVu":"cư dân","tuChuong":"@c0374","trangThai":"sinh sống trên đảo"}],"tabs":{"tienTrinh":[{"chuong":"@c0374","loai":"nhắc tới","importance":"normal","giaiDoan":"Lệ nhận linh thạch","text":"Cư dân Tiểu Hoàn Đảo quen với bạch vụ quanh động phủ, còn trưởng trấn đứng ngoài bạch vụ gọi Hàn tiên sư để nhận linh thạch duy trì trận pháp.","anchor":"chỉ cần trưởng trấn đứng ở bên ngoài bạch vụ hướng về phía ngọn núi kêu lớn vài tiếng"}]},"nguon":["@c0374"]},{"id":"tan-tu-phu-can-dao","name":"Tán tu phụ cận đảo","cn":null,"type":"khac","typeLabel":"Nhóm tán tu","diaBan":"Khôi Tinh Đảo","nhanVatChinh":["Nghiên Lệ","Nguyên Dao"],"blurb":"Nhóm tán tu hoạt động quanh đảo, được nhắc qua lời giới thiệu của Nghiên Lệ và Nguyên Dao. Họ lui tới Thiên Đô Nhai để xem các tài liệu trân quý vừa được đưa tới.","detail":"Chương này chỉ xác nhận Nghiên Lệ và Nguyên Dao tự xưng là tán tu phụ cận đảo, chưa thấy cơ cấu hay quy mô cụ thể.","thanhVien":[{"ten":"Nghiên Lệ","chucVu":"Tán tu","tuChuong":"@c0375","trangThai":"hoạt động"},{"ten":"Nguyên Dao","chucVu":"Tán tu","tuChuong":"@c0375","trangThai":"hoạt động"}],"capNhatToi":"@c0375","nguon":["@c0375"]},{"id":"luc-lien-dien","name":"Lục Liên Điện","cn":"六联殿","type":"thuong-hoi","typeLabel":"Thế lực thương mại tu tiên","diaBan":"Trung tâm Thiên Đô Nhai","nhanVatChinh":["Tào Lộc","Âu Dương đạo hữu"],"blurb":"Lục Liên Điện là mạng lưới thế lực có khả năng phối hợp đồng thời nhiều lâu các để tìm kiếm linh vật quý hiếm tại Thiên Đô Nhai. Tổ chức này từng bị phản loạn nội bộ trong một đêm cùng với bảy tám thế lực lớn nhỏ khác, dẫn đến thủ lãnh mất quyền kiểm soát.","detail":"Lục Liên Điện hoạt động như một hệ thống liên kết nhiều cơ sở giao dịch, có năng lực điều phối đồng thời các tuyến tìm kiếm linh vật hiếm phục vụ Kết Đan. Trong giao dịch tại Bạch Thủy Lâu, Tào Lộc nhắc tới Lục Liên Điện khi cần tìm cùng lúc Tuyết Linh Thủy và Thiên Hỏa Dịch, đồng thời liên hệ Âu Dương đạo hữu của Ngọc Hoàn Cư, cho thấy các lâu các như Bạch Thủy Lâu và Ngọc Hoàn Cư nằm trong cùng mạng lưới giao dịch của Lục Liên Điện. Về sau, Lục Liên Điện cùng bảy tám thế lực lớn nhỏ khác đồng loạt bị phản loạn nội bộ trong một đêm, thủ lãnh hoặc tông chủ bị mất quyền, cho thấy tổ chức này đã trở thành mục tiêu trong một cuộc thanh trừng hoặc lật đổ có quy mô và tính toán kỹ lưỡng.","thanhVien":[{"ten":"Tào Lộc","chucVu":"Chưởng quầy Bạch Thủy Lâu","tuChuong":"@c0376","trangThai":"hoạt động"},{"ten":"Âu Dương đạo hữu","chucVu":"Người của Ngọc Hoàn Cư","tuChuong":"@c0376","trangThai":"hoạt động"}],"quanHe":"Liên hệ phối hợp giữa Bạch Thủy Lâu và Ngọc Hoàn Cư trong giao dịch linh vật","tabs":{"tienTrinh":[{"chuong":"@c0376","loai":"nhắc tới","importance":"normal","giaiDoan":"Phối hợp tìm linh vật","text":"Tào Lộc nói việc tìm Tuyết Linh Thủy và Thiên Hỏa Dịch cần Lục Liên Điện đồng thời tiến hành, rồi liên hệ Âu Dương đạo hữu của Ngọc Hoàn Cư.","anchor":"sự tình này thì phải cần có Lục Liên Điện chúng tôi đồng thời tiến hành"},{"chuong":"@c0415","loai":"đổi lãnh đạo","importance":"major","giaiDoan":"Phản loạn đồng loạt","trangThaiMoc":"Mất quyền lãnh đạo","text":"Cùng bảy tám thế lực lớn nhỏ đồng thời bị phản loạn nội bộ trong một đêm, thủ lãnh/tông chủ mất quyền, bị người vô danh tiếp quản.","anchor":"“Lục Liên điện” cùng với bảy, tám thể lực lớn nhỏ khác nhau, đột nhiên trong một đêm đồng thời xuất hiện thuộc hạ hoặc là đệ tử phản loạn"}]},"capNhatToi":"@c0376","nguon":["@c0376","@c0415","@c0498"],"trangThai":"bị phản loạn, mất quyền lãnh đạo","dacDiem":"Là mạng lưới liên kết đa thế lực có khả năng điều phối đồng thời, nhưng từng bị phản loạn nội bộ trong một đêm cùng nhiều thế lực khác, thủ lãnh mất quyền @c0415","congNang":["Phối hợp đồng thời nhiều tuyến tìm kiếm linh vật quý hiếm phụ trợ Kết Đan, như Tuyết Linh Thủy và Thiên Hỏa Dịch @c0376","Liên kết nhiều lâu các giao dịch (Bạch Thủy Lâu, Ngọc Hoàn Cư) trong cùng mạng lưới @c0376"]},{"id":"bach-thuy-lau","name":"Bạch Thủy Lâu","cn":"","type":"cua-hang","typeLabel":"Cửa hàng pháp khí","diaBan":"Quảng trường trung tâm Thiên Đô Nhai","nhanVatChinh":["Tào Lộc","Tiểu nhị áo xanh của Bạch Thủy Lâu","Nữ tỳ Bạch Thủy Lâu"],"blurb":"Bạch Thủy Lâu là một trong sáu lâu các quanh quảng trường trung tâm Thiên Đô Nhai. Nơi này bày bán pháp khí, tiếp Hàn Lập và Khúc Hồn trong phòng trong, đồng thời là điểm khởi đầu giao dịch Tuyết Linh Thủy và Thiên Hỏa Dịch.","detail":"Bạch Thủy Lâu treo tiêu thức thanh tiểu kiếm màu vàng, bên trong có đại sảnh rộng và các giá bạch ngọc bày gần trăm pháp khí. Khi Khúc Hồn lộ tu vi Trúc Cơ cao giai, tiểu nhị mời vào phòng trong, chưởng quầy Tào Lộc ra tiếp và liên hệ Âu Dương đạo hữu của Ngọc Hoàn Cư.","thanhVien":[{"ten":"Tào Lộc","chucVu":"Chưởng quầy","tuChuong":"@c0376","trangThai":"hoạt động"},{"ten":"Tiểu nhị áo xanh của Bạch Thủy Lâu","chucVu":"Tiểu nhị tiếp khách","tuChuong":"@c0376","trangThai":"hoạt động"},{"ten":"Nữ tỳ Bạch Thủy Lâu","chucVu":"Người hầu tiếp trà","tuChuong":"@c0376","trangThai":"hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0376","loai":"nhắc tới","importance":"normal","giaiDoan":"Tiếp Hàn Lập và Khúc Hồn","text":"Bạch Thủy Lâu tiếp Hàn Lập và Khúc Hồn, trưng bày pháp khí và để Tào Lộc đứng ra giao dịch linh vật phụ trợ Kết Đan.","anchor":"Bạch Thủy Lâu lại mà một thanh tiểu kiếm màu vàng"}]},"capNhatToi":"@c0376","nguon":["@c0376"]},{"id":"ngoc-hoan-cu","name":"Ngọc Hoàn Cư","cn":"","type":"cua-hang","typeLabel":"Cửa hàng trong Lục Liên Điện","diaBan":"Quảng trường trung tâm Thiên Đô Nhai","nhanVatChinh":["Âu Dương đạo hữu"],"blurb":"Ngọc Hoàn Cư là một trong các lâu các quanh quảng trường trung tâm Thiên Đô Nhai. Âu Dương đạo hữu thuộc nơi này và được Tào Lộc liên hệ để mang Tuyết Linh Thủy cùng Thiên Hỏa Dịch tới Bạch Thủy Lâu.","detail":"Ngọc Hoàn Cư treo tiêu thức linh chi thảo màu xanh. Khi Khúc Hồn hỏi mua linh vật phụ trợ Kết Đan, Tào Lộc truyền tin cho Âu Dương đạo hữu của Ngọc Hoàn Cư, sau đó Âu Dương mang hai hộp ngọc chứa Tuyết Linh Thủy và Thiên Hỏa Dịch đến.","thanhVien":[{"ten":"Âu Dương đạo hữu","chucVu":"Người mang linh vật giao dịch","tuChuong":"@c0376","trangThai":"hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0376","loai":"nhắc tới","importance":"normal","giaiDoan":"Cung cấp linh vật","text":"Ngọc Hoàn Cư được nhắc tới khi Tào Lộc liên hệ Âu Dương đạo hữu để mang hai linh vật phụ trợ Kết Đan sang Bạch Thủy Lâu.","anchor":"liền thay đạo hữu liên hệ đến Âu Dương đạo hữu của Ngọc Hoàn Cư"}]},"capNhatToi":"@c0376","nguon":["@c0376"]},{"id":"cuc-am-dao","name":"Cực Âm Đảo","cn":"極陰島","aliases":[],"type":"dao-phai","typeLabel":"Thế lực đảo tu tiên","diaBan":"Loạn Tinh Hải","nhanVatChinh":["Ô Sửu","Cực âm lão tổ","Cực Âm tổ sư","Hàn Lập"],"blurb":"Cực Âm Đảo là thế lực ma đạo hoạt động tại Loạn Tinh Hải, đứng đầu là Cực Âm tổ sư (Cực Âm lão tổ). Thế lực này có uy danh đủ lớn để uy hiếp các môn phái khác như Lục Liên Điện, Diệu Âm Môn, và từng cướp hàng, giết trưởng lão rồi giá họa cho Ẩn Sát Môn, đồng thời ép buộc tu sĩ hai phe quy thuận.","detail":"Cực Âm Đảo là một thế lực ma đạo tại Loạn Tinh Hải, do Cực Âm tổ sư (còn gọi Cực Âm lão tổ) lãnh đạo. Thuộc hạ đáng chú ý có Ô Sửu, người thường nhân danh Cực Âm Đảo để đe dọa và tranh đoạt với các thế lực khác. Ô Sửu từng dùng danh Cực Âm Đảo ép Lục Liên Điện nhường Anh Lý Thú, khiến tu sĩ xung quanh kiêng sợ biến sắc (@c0382). Cực Âm Đảo còn cướp hàng của Diệu Âm Môn, giết hai trưởng lão của môn phái này và giá họa cho Ẩn Sát Môn (@c0405). Cực Âm tổ sư từng uy hiếp toàn bộ tu sĩ hai phe, yêu cầu quy thuận Cực Âm Đảo và mỗi người phải giao ba phần nguyên thạch (@c0406). Về lai lịch, Cực Âm lão tổ có sư phụ là một quái ảnh, vị này gọi hắn là nghịch đồ, và giữa hai người có liên quan đến Huyết Luyện thân quang (@c0426). Về sau, Cực Âm tổ sư thu nhận Hàn Lập làm ký danh đệ tử, mở rộng nhân s","lanhDaoHienThoi":"Cực âm lão tổ","quanHe":"Đối đầu lợi ích với Lục Liên Điện trong vụ tranh đoạt Anh Lý Thú.","trangThai":"hoat-dong","thanhVien":[{"ten":"Ô Sửu","chucVu":"Đệ tử","tuChuong":"@c0382","trangThai":"hoat-dong"},{"ten":"Cực Âm lão tổ","chucVu":"Tổ sư / Đảo chủ","tuChuong":"@c0382","trangThai":"hoat-dong"},{"ten":"Triệu trưởng lão","chucVu":"Nội gián trong Diệu Âm Môn","tuChuong":"@c0405","trangThai":"dang-hoat-dong"},{"ten":"Mạnh trưởng lão","chucVu":"Nội gián trong Diệu Âm Môn","tuChuong":"@c0405","trangThai":"dang-hoat-dong"},{"ten":"Hàn Lập","chucVu":"Ký danh đệ tử","tuChuong":"@c0456","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0382","loai":"nhắc tới","importance":"normal","giaiDoan":"Ép Lục Liên Điện","text":"Ô Sửu lấy danh Cực Âm Đảo để ép Lục Liên Điện nhường Anh Lý Thú và khiến các tu sĩ xung quanh kiêng sợ.","trangThaiMoc":"uy danh được dùng để uy hiếp","anchor":"Lục Liên Điện các vị chắc không phải không cho Cực Âm Đảo chúng ta một chút mặt mũi"},{"chuong":"@c0405","loai":"nhắc tới","importance":"major","giaiDoan":"Lộ toàn bộ âm mưu","text":"Ô Sửu công khai thừa nhận Cực Âm đảo cướp hàng Diệu Âm Môn, giết hai trưởng lão và giá họa Ẩn Sát Môn. Cực Âm lão tổ dùng phụ thân thuật chiếm thân Ô Sửu đích thân hành động.","anchor":"hàng hóa của Diệu Âm Môn các ngươi do người của bổn đảo cướp, nhị vị trưởng lão cũng do bổn thiếu chủ phân phó giá họa cho Ẩn Sát Môn"},{"chuong":"@c0406","loai":"mo-rong","importance":"major","giaiDoan":"Bành trướng ép quy phục","text":"Cực Âm tổ sư uy hiếp toàn bộ tu sĩ hai phe phải quy thuận Cực Âm đảo, yêu cầu mỗi người giao ba phần nguyên thần lên Cấm Thần bài.","anchor":"từ nay về sau, các ngươi đồng ý quy thuận Cực Âm đảo thì có thể tiếp tục tiêu diêu tự tại"},{"chuong":"@c0426","loai":"nhắc tới","importance":"major","giaiDoan":"Lộ bí mật truyền thừa","text":"Quái ảnh lộ ra là sư phụ Cực Âm lão tổ, gọi hắn là nghịch đồ. Huyết Luyện thân quang liên quan cả Cực Âm lẫn Cực Huyễn, hai nhánh truyền thừa cùng nguồn gốc.","anchor":"Tên nghịch đồ như hắn mà dám tự xưng là tổ sư sao?"},{"chuong":"@c0456","loai":"mở rộng/mất địa bàn","importance":"normal","giaiDoan":"Thu Hàn Lập làm ký danh đệ tử","text":"Cực Âm tổ sư thu Hàn Lập làm ký danh đệ tử, mở rộng nhân sự thế lực.","anchor":"Chẳng những tu sĩ đông đảo, thế lực to lớn, làm thân truyền đệ tử cho bổn tổ sư sẽ có quyền thế"}]},"capNhatToi":"@c0382","nguon":["@c0382","@c0405","@c0406","@c0426","@c0456"],"uyLuc":"Cực Âm tổ sư có khả năng uy hiếp toàn bộ tu sĩ hai phe buộc phải quy thuận, cho thấy sức mạnh áp đảo cấp vùng tại Loạn Tinh Hải (@c0406).","dacDiem":"Thế lực ma đạo hành sự ngang ngược, sẵn sàng cướp đoạt, giết chóc và giá họa cho người khác; dùng uy danh để đe nẹt, buộc các thế lực xung quanh quy phục.","congNang":["Dùng uy danh Cực Âm Đảo để uy hiếp, buộc thế lực khác nhường chiến lợi phẩm (@c0382)","Cướp hàng của môn phái khác (Diệu Âm Môn) và giá họa cho thế lực thứ ba (Ẩn Sát Môn) (@c0405)","Uy hiếp tu sĩ hai phe quy thuận, bắt giao nộp nguyên thạch (@c0406)","Thu nhận ký danh đệ tử để mở rộng nhân sự thế lực (@c0456)"]},{"id":"vi-tinh-dao-faction","name":"Vĩ Tinh Đảo","cn":"","type":"dao-luc","typeLabel":"Đảo lực","diaBan":"Vĩ Tinh Đảo","nhanVatChinh":["Mao sư đệ môn hạ đảo chủ Vĩ Tinh Đảo"],"blurb":"Thế lực được nhắc qua thân phận Mao sư đệ là môn hạ của đảo chủ Vĩ Tinh Đảo. Cái chết của người này được nhóm chấp pháp dùng làm căn cứ buộc tội Hàn Lập và Khúc Hồn.","detail":"Trong lời cáo buộc ngoài tiểu đảo, lão giả đầu bạc nói Hàn Lập và Khúc Hồn vì Hàng Trần Đan mà sát hại Mao sư đệ thuộc môn hạ đảo chủ Vĩ Tinh Đảo.","thanhVien":[{"ten":"Trung niên nho sinh","chucVu":"Mao sư đệ môn hạ đảo chủ Vĩ Tinh Đảo","tuChuong":"@c0388","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0388","loai":"nhắc tới","importance":"bridge","giaiDoan":"Môn hạ bị nêu trong cáo buộc","text":"Vĩ Tinh Đảo được nhắc qua thân phận Mao sư đệ trong lời buộc tội Hàn Lập và Khúc Hồn.","trangThaiMoc":"được nhắc tới","anchor":"Mao sư đệ môn hạ của đảo chủ Vĩ Tinh Đảo"}]},"capNhatToi":"@c0388","nguon":["@c0388"]},{"id":"tinh-cung","name":"Tinh Cung","cn":"","aliases":["Thiên Tinh Cung"],"type":"the-luc","typeLabel":"Thế lực quản hạt","diaBan":"Thiên Tinh Thành, Loạn Tinh Hải","nhanVatChinh":["Thiên Tinh Song Thánh"],"blurb":"Tinh Cung là thế lực lớn quản hạt toàn bộ Loạn Tinh Hải, đặt trung tâm tại Thiên Tinh Thành. Tổ chức do Thiên Tinh Song Thánh thống trị, nắm quyền kiểm soát hệ thống tinh đảo trong Nội Tinh Hải lẫn tuyến liên thông ra Ngoại Tinh Hải.","detail":"Tinh Cung là thế lực có nguồn gốc lâu đời, được truyền thuyết hóa trong điển tịch Loạn Tinh Hải. Tổ chức này quản hạt toàn bộ vùng Loạn Tinh Hải hiện tại, lấy Thiên Tinh Thành làm trung tâm quyền lực. Đứng đầu Tinh Cung là hai vị thành chủ được xưng tụng Thiên Tinh Song Thánh. Tinh Cung nắm cơ chế bổ nhiệm đảo chủ các tinh đảo, tổ chức Trích Tinh đại hội và xây dựng truyền tống trận liên thông đến Ngoại Tinh Hải.","nguonGoc":"Nguồn gốc lâu đời và được truyền thuyết hóa trong điển tịch Loạn Tinh Hải.","lanhDaoHienThoi":"Thiên Tinh Song Thánh","quyMo":"Quản hạt Loạn Tinh Hải và hệ thống tinh đảo trong ngoài Nội Tinh Hải.","quanHe":"Là siêu cấp thế lực bao trùm, bên cạnh vẫn tồn tại các thế lực lớn nhỏ khác như Dạ Long Đảo, Tứ Đại Thương Minh, Mị Ma Tông và Tam Tiên Môn.","trangThai":"đang quản hạt Loạn Tinh Hải","thanhVien":[{"ten":"Thiên Tinh Song Thánh","chucVu":"thành chủ, người thống trị Tinh Cung","tuChuong":"@c0389","trangThai":"đương nhiệm"}],"lanhDaoMoc":[{"ten":"Thiên Tinh Song Thánh","tuChuong":"@c0389","denChuong":""}],"tabs":{"tienTrinh":[{"chuong":"@c0389","loai":"nhắc tới","importance":"major","giaiDoan":"Xác lập quyền quản hạt","text":"Tinh Cung được giới thiệu là thế lực lớn đang quản hạt cả Loạn Tinh Hải, đặt trung tâm tại Thiên Tinh Thành và do Thiên Tinh Song Thánh thống trị.","anchor":"Ngày nay, cả Loạn Tinh Hải đều do một thế lực lớn gọi là “Tinh Cung” quản hạt.","trangThaiMoc":"quản hạt Loạn Tinh Hải"}]},"capNhatToi":"@c0389","nguon":["@c0389"]},{"id":"da-long-dao","name":"Dạ Long Đảo","cn":"","aliases":[],"type":"the-luc","typeLabel":"Thế lực hải đảo","diaBan":"Loạn Tinh Hải","nhanVatChinh":[],"blurb":"Một thế lực ngoài Tinh Cung được điển tịch liệt kê trong Loạn Tinh Hải. Chưa có thành viên, địa bàn chi tiết hay hành động riêng được nêu.","detail":"Dạ Long Đảo được nhắc cùng Tứ Đại Thương Minh, Mị Ma Tông và Tam Tiên Môn như một trong các thế lực lớn nhỏ tồn tại bên ngoài Tinh Cung tại Loạn Tinh Hải.","quyMo":"Thế lực ngoài Tinh Cung tại Loạn Tinh Hải.","tabs":{"tienTrinh":[{"chuong":"@c0389","loai":"nhắc tới","importance":"bridge","giaiDoan":"Liệt kê thế lực Loạn Tinh Hải","text":"Dạ Long Đảo được liệt kê là một thế lực ngoài Tinh Cung trong Loạn Tinh Hải.","anchor":"tỷ như “Dạ Long Đảo”, “Tứ Đại Thương Minh”, “Mị Ma Tông”, “Tam Tiên Môn”","trangThaiMoc":"được nhắc tới"}]},"capNhatToi":"@c0389","nguon":["@c0389"]},{"id":"tu-dai-thuong-minh","name":"Tứ Đại Thương Minh","cn":"","aliases":[],"type":"thuong-minh","typeLabel":"Thương minh","diaBan":"Loạn Tinh Hải","nhanVatChinh":[],"blurb":"Một thế lực thương minh được nhắc trong danh sách các thế lực ngoài Tinh Cung. Chương chưa nêu thành viên hay phạm vi hoạt động cụ thể.","detail":"Tứ Đại Thương Minh xuất hiện trong điển tịch như một trong những thế lực lớn nhỏ cùng tồn tại tại Loạn Tinh Hải bên cạnh Tinh Cung.","quyMo":"Thế lực ngoài Tinh Cung tại Loạn Tinh Hải.","tabs":{"tienTrinh":[{"chuong":"@c0389","loai":"nhắc tới","importance":"bridge","giaiDoan":"Liệt kê thế lực Loạn Tinh Hải","text":"Tứ Đại Thương Minh được liệt kê là một thế lực ngoài Tinh Cung trong Loạn Tinh Hải.","anchor":"tỷ như “Dạ Long Đảo”, “Tứ Đại Thương Minh”, “Mị Ma Tông”, “Tam Tiên Môn”","trangThaiMoc":"được nhắc tới"},{"chuong":"@c0511","loai":"nhan-toi","importance":"normal","giaiDoan":"Mất quyền kiểm soát Kỳ Uyên đảo","text":"Từng đại chiến nhiều trận tranh giành Hải uyên yêu thú với các thế lực bản địa, cuối cùng Tinh Cung hòa giải, mất quyền lũng đoạn Kỳ Uyên đảo.","anchor":"Có lẽ các Yêu Thú đảo khác đều bị tứ đại thương minh lũng đoạn"}]},"capNhatToi":"@c0389","nguon":["@c0389","@c0511"],"trangThai":"hung"},{"id":"mi-ma-tong","name":"Mị Ma Tông","cn":"","aliases":[],"type":"tong-mon","typeLabel":"Tông môn","diaBan":"Loạn Tinh Hải","nhanVatChinh":[],"blurb":"Một tông môn được nhắc trong danh sách thế lực ngoài Tinh Cung tại Loạn Tinh Hải. Chương chưa nêu nhân vật hoặc hành động riêng của tông môn này.","detail":"Mị Ma Tông được liệt kê cùng Dạ Long Đảo, Tứ Đại Thương Minh và Tam Tiên Môn như một trong các thế lực lớn nhỏ ngoài Tinh Cung.","quyMo":"Thế lực ngoài Tinh Cung tại Loạn Tinh Hải.","tabs":{"tienTrinh":[{"chuong":"@c0389","loai":"nhắc tới","importance":"bridge","giaiDoan":"Liệt kê thế lực Loạn Tinh Hải","text":"Mị Ma Tông được liệt kê là một thế lực ngoài Tinh Cung trong Loạn Tinh Hải.","anchor":"tỷ như “Dạ Long Đảo”, “Tứ Đại Thương Minh”, “Mị Ma Tông”, “Tam Tiên Môn”","trangThaiMoc":"được nhắc tới"}]},"capNhatToi":"@c0389","nguon":["@c0389"]},{"id":"tam-tien-mon","name":"Tam Tiên Môn","cn":"","aliases":[],"type":"tong-mon","typeLabel":"Tông môn","diaBan":"Loạn Tinh Hải","nhanVatChinh":[],"blurb":"Một thế lực được điển tịch liệt kê tại Loạn Tinh Hải ngoài Tinh Cung. Thông tin hiện mới dừng ở mức được nhắc tên trong danh sách thế lực.","detail":"Tam Tiên Môn được nêu cùng Dạ Long Đảo, Tứ Đại Thương Minh và Mị Ma Tông khi Hàn Lập đọc điển tịch về các thế lực lớn nhỏ ở Loạn Tinh Hải.","quyMo":"Thế lực ngoài Tinh Cung tại Loạn Tinh Hải.","tabs":{"tienTrinh":[{"chuong":"@c0389","loai":"nhắc tới","importance":"bridge","giaiDoan":"Liệt kê thế lực Loạn Tinh Hải","text":"Tam Tiên Môn được liệt kê là một thế lực ngoài Tinh Cung trong Loạn Tinh Hải.","anchor":"tỷ như “Dạ Long Đảo”, “Tứ Đại Thương Minh”, “Mị Ma Tông”, “Tam Tiên Môn”","trangThaiMoc":"được nhắc tới"}]},"capNhatToi":"@c0389","nguon":["@c0389"]},{"id":"thien-tinh-thanh-faction","name":"Thiên Tinh Thành","cn":"天星城","aliases":[],"type":"thanh-thi","typeLabel":"Thành thị","diaBan":"Thiên Tinh Thành, Loạn Tinh Hải","nhanVatChinh":[],"blurb":"Thế lực quản lý đô thị tại đệ nhất đại thành của Loạn Tinh Hải, có quy chế thu phí và cấp thân phận hoàn cho tu sĩ vào thành.","detail":"Tu sĩ Kết Đan kỳ trở lên được miễn phí tổn khi cư trú. Tu sĩ thường muốn ở lâu phải nộp tám trăm linh thạch mua hồng sắc thân phận hoàn. Cửa thành do tu sĩ Trúc Cơ sơ kỳ áo trắng phụ trách. Nội thành không có cấm chế phi hành.","nguonGoc":"","capBac":"Đệ nhất đại thành Loạn Tinh Hải","trangThai":"Đang hoạt động","thanhVien":[{"ten":"Hai tu sĩ áo trắng canh cửa Thiên Tinh Thành","chucVu":"Canh cửa thành","tuChuong":"@c0390","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0390","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ cơ chế quản lý cư trú","trangThaiMoc":"Đang hoạt động","text":"Hé lộ quy chế thân phận hoàn với hai loại lam sắc (tạm trú bảy ngày, ba linh thạch) và hồng sắc (vĩnh viễn, tám trăm linh thạch). Tu sĩ Kết Đan kỳ miễn phí.","anchor":"Dựa theo quy định của bổn thành, tu sĩ Kết Đan Kỳ không cần nạp phí tổn"}]},"capNhatToi":"@c0390","nguon":["@c0390"]},{"id":"bach-mon-cac","name":"Bạch Môn Các","type":"thuong-diem","typeLabel":"Thư điếm","diaBan":"Phường thị Thiên Tinh Thành","nhanVatChinh":[],"blurb":"Thư điếm tại phường thị Thiên Tinh Thành, lưu giữ tư liệu yêu thú Loạn Tinh Hải, nơi Hàn Lập chi hơn một trăm linh thạch sao chép tài liệu chuẩn bị ra biển.","detail":"Hiệu sách có hệ thống tư liệu đầy đủ về các yêu thú từ trước đến nay ở Loạn Tinh Hải, Hàn Lập cùng Khúc Hồn đến sao chép làm cơ sở nghiên cứu.","nguon":["@c0393"]},{"id":"phong-dau-gia-phong-nhac","name":"Phòng đấu giá Phong Nhạc","type":"thuong-diem","typeLabel":"Phòng đấu giá","diaBan":"Phường thị Thiên Tinh Thành","nhanVatChinh":[],"blurb":"Phòng đấu giá đệ nhất Thiên Tinh Thành, có mục lục đấu giá yêu đan cấp năm, cấp sáu cùng tài liệu luyện pháp bảo cao cấp, nhưng giá bị đẩy cao khiến tu sĩ tầm trung không thể tham gia.","detail":"Hàn Lập đi ngang thấy mục lục có yêu đan cấp cao và nhiều vật phẩm quý chưa từng nghe, nhưng tự biết chỉ có mấy ngàn linh thạch không đủ cạnh tranh. Dù có thể bán thiên niên linh thảo giá cao ở đây, hắn chọn không chuốc phiền.","nguon":["@c0393"]},{"id":"tinh-khong-dien","name":"Tinh Không Điện","type":"co-so","typeLabel":"Cơ sở truyền tống","diaBan":"Tầng năm mươi Thiên Tinh Thành","nhanVatChinh":[],"blurb":"Đại điện đá Đại Lý màu trắng tại tầng năm mươi Thiên Tinh Thành, do tu sĩ Thiên Tinh Cung quản lý, chứa nhiều truyền tống trận dẫn tới các yêu thú đảo trong Ngoại Tinh Hải.","detail":"Bên trong có bạch y tu sĩ Kết Đan thuộc Tinh Cung quản trận, phía sau đại sảnh đặt nhiều truyền tống trận ghi rõ địa điểm đến. Truyền tống tính theo lượt, tối đa bảy người mỗi lượt, phí bảy trăm linh thạch. Tu sĩ được phát Truyền tống phù bảo vệ trước khi khởi động.","nguon":["@c0393"]},{"id":"phong-nhac-thuong-minh","name":"Phong Nhạc thương minh","cn":"","type":"thuong-hoi","typeLabel":"Thương hội","diaBan":"Thiên Tinh Thành, Ngưng Thúy Đảo","nhanVatChinh":["Chưởng quỹ tạp hóa Phong Nhạc","Phạm tiểu tử"],"blurb":"Một trong Tứ đại thương minh, tại Thiên Tinh Thành mở Phong Nhạc đấu giá hành, trên Ngưng Thúy Đảo mở cửa hiệu tạp hóa và nhà thu mua hàng hóa.","detail":"Thương minh lớn hoạt động trong vùng Ngoại tinh hải. Tại Thiên Tinh Thành mở Phong Nhạc đấu giá hành. Trên Ngưng Thúy Đảo có cửa hiệu tạp hóa (bán Hải Vực Đồ, tạp vật) và nhà thu mua hàng hóa phía Tây (thu mua thi thể yêu thú, yêu đan). Nhân viên gồm tu sĩ Luyện khí kỳ.","nguonGoc":"","quyMo":"Tứ đại thương minh","thanhVien":[{"ten":"Chưởng quỹ tạp hóa Phong Nhạc","chucVu":"Chưởng quỹ cửa hiệu tạp hóa Ngưng Thúy Đảo","tuChuong":"@c0394","trangThai":"dang-hoat-dong"},{"ten":"Phạm tiểu tử","chucVu":"Nhân viên nhà thu mua hàng hóa Ngưng Thúy Đảo","tuChuong":"@c0394","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0394","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện trên Ngưng Thúy Đảo","text":"Hàn Lập vào cửa hiệu tạp hóa Phong Nhạc thương minh mua Hải Vực Đồ. Được biết đây là một trong Tứ đại thương minh, tại Thiên Tinh Thành mở Phong Nhạc đấu giá hành.","anchor":"Phong Nhac minh là một trong Tứ đại thương minh, tại Thiên Tinh Thành mở Phong nhạc đấu giá hành"}]},"capNhatToi":"@c0394","nguon":["@c0394"]},{"id":"dieu-am-mon","name":"Diệu Âm Môn","cn":"妙音门","type":"mon-phai","typeLabel":"Môn phái","nhanVatChinh":["Phạm Tĩnh Mai","Liên nhi","Trác Như Đình","Tử Linh Tiên Tử","Tu sĩ ma đạo họ Vân","Vân Thiên Khiếu"],"blurb":"Diệu Âm Môn là một môn phái có đệ tử thông thạo mị thuật, từng chủ động tiếp cận Hàn Lập để bàn mua tài liệu yêu thú trân quý. Nội bộ môn phái trải qua biến động lớn khi Phạm tả sứ cùng tu sĩ ma đạo họ Vân đoạt quyền trong lúc Tử Linh Tiên Tử vắng mặt, khiến thực quyền rơi vào tay Vân Thiên Khiếu và hơn phân nửa đệ tử chịu ảnh hưởng.","detail":"Diệu Âm Môn là môn phái có tổ chức phân cấp rõ ràng, với các chức vị tả sứ, hữu sứ và chưởng môn (Tử Linh Tiên Tử). Phạm Tĩnh Mai, xưng thuộc Diệu Âm Môn, từng sai đệ tử Liên nhi (tu sĩ Luyện Khí kỳ, biết mị thuật) chặn đường mời Hàn Lập đến Thanh Hà trà quán, nơi đã bố trí phòng riêng với lão giả áo xám bí ẩn ngồi chờ sẵn, thái độ bình thản trước Kết Đan kỳ tu sĩ, nhằm bàn mua tài liệu yêu thú trân quý (@c0399). Môn phái có nữ đệ tử thân truyền là Trác hữu sứ, từng cùng một nam tu sĩ bị ba tu sĩ Độc Long hội truy đánh và nhận ra Hàn Lập (@c0429). Khi Tử Linh Tiên Tử vào Hư Thiên Điện, Phạm tả sứ câu kết với tu sĩ ma đạo họ Vân đoạt đại quyền, Trác hữu sứ mất tích (@c0538). Phạm phu nhân sau đó thừa nhận mình chỉ là con rối, thực quyền Diệu Âm Môn nằm trong tay Vân Thiên Khiếu, hơn phân nử","thanhVien":[{"ten":"Phạm Tĩnh Mai","chucVu":"Chưởng môn (danh nghĩa)","tuChuong":"@c0399","trangThai":"dang-giu"},{"ten":"Liên nhi","chucVu":"Đệ tử","tuChuong":"@c0399","trangThai":"hien-dien"},{"ten":"Lão giả áo xám (tại trà quán)","chucVu":"Chưa rõ, có vẻ bề trên","tuChuong":"@c0399","trangThai":"hien-dien"},{"ten":"Trác Như Đình","chucVu":"Hữu sứ","tuChuong":"@c0429","trangThai":"mat-tich"},{"ten":"Nữ đệ tử Diệu Âm môn","chucVu":"Đệ tử thân truyền Trác hữu sử","tuChuong":"@c0429","trangThai":"hoat-dong"},{"ten":"Tu sĩ ma đạo họ Vân","chucVu":"Đồng mưu","tuChuong":"@c0538","trangThai":"dang-hoat-dong"},{"ten":"Tử Linh Tiên Tử","chucVu":"Thiếu môn chủ (cựu)","tuChuong":"@c0538","trangThai":"da-roi"},{"ten":"Văn Tư Nguyệt","chucVu":"Đệ tử","tuChuong":"@c0538","trangThai":"da-roi"},{"ten":"Vân Thiên Khiếu","chucVu":"Thực quyền khống chế","tuChuong":"@c0554","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c0399","loai":"xuat-hien","importance":"normal","giaiDoan":"Xuất hiện","text":"Diệu Âm Môn qua Phạm Tĩnh Mai chủ động tiếp cận Hàn Lập bàn mua tài liệu yêu thú trân quý, bố trí kỹ lưỡng tại Thanh Hà trà quán.","anchor":"Vãn bối Diệu Âm môn Phạm Tĩnh Mai xin bái kiến tiền bối"},{"chuong":"@c0429","loai":"nhắc tới","importance":"normal","giaiDoan":"Đệ tử bị Độc Long hội truy đánh","text":"Nữ đệ tử thân truyền Trác hữu sử cùng một nam tu sĩ bị ba tu sĩ Độc Long hội truy đánh, nhận ra Hàn Lập bay ngang và cầu cứu.","anchor":"ta là đệ tử thân truyền của Trác hữu sử Diệu Âm môn, mong Hàn trưởng lão tương trợ"},{"chuong":"@c0538","loai":"đổi lãnh đạo","importance":"major","giaiDoan":"Phạm tả sứ đoạt quyền, tự lập chưởng môn","text":"Phạm tả sứ cùng tu sĩ ma đạo họ Vân đoạt đại quyền khi Tử Linh Tiên Tử vào Hư Thiên Điện. Trác hữu sứ mất tích. Phạm tả sứ tự lập chưởng môn, mang đệ tử truyền tống đến Kỳ Uyên đảo lập bí thị, thanh trừ đệ tử bất phục. Môn phái phụ thuộc ma đạo.","trangThaiMoc":"phụ thuộc ma đạo","anchor":"Diệu Âm môn đã phụ thuộc vào ma đạo rồi"},{"chuong":"@c0554","loai":"nhắc tới","importance":"normal","giaiDoan":"Nội bộ bị thao túng, bí công bị đánh cắp","trangThaiMoc":"Suy","text":"Phạm phu nhân thừa nhận mình chỉ là con rối tại Diệu Âm môn, Vân Thiên Khiếu nắm thực quyền. Hơn phân nửa đệ tử canh Truyền tống trận là người của hắn. Ngọc giản bí công mị thuật bổn môn bị mất.","anchor":"tại Diệu Âm môn này thiếp thân không khác gì một con rối"}]},"capNhatToi":"@c0399","nguon":["@c0399","@c0429","@c0498","@c0538","@c0554"],"trangThai":"Suy, nội bộ bị thao túng","dacDiem":"Nội bộ phân cấp rõ ràng (chưởng môn, tả sứ, hữu sứ), nhưng dễ bị thao túng khi chưởng môn vắng mặt; từng bị tu sĩ ma đạo Vân Thiên Khiếu nắm thực quyền, biến Phạm tả sứ thành con rối và khống chế hơn phân nửa đệ tử.","congNang":["Đệ tử sử dụng mị thuật (Liên nhi, Luyện Khí kỳ) @c0399","Bố trí tiếp cận, sắp xếp giao dịch mua bán tài liệu yêu thú trân quý một cách kỹ lưỡng, có phòng riêng và nhân sự chờ sẵn @c0399"]},{"id":"nguyen-quy-dao","name":"Nguyên Quy Đảo","cn":"","type":"the-luc","typeLabel":"Lãnh địa cá nhân","diaBan":"Loạn Tinh Hải","nhanVatChinh":["Xích Hỏa lão quái"],"blurb":"Hải đảo bị Xích Hỏa lão quái (Kết Đan hậu kỳ) độc chiếm, không ai dám trêu chọc.","detail":"Đảo trên Loạn Tinh Hải do Xích Hỏa lão quái một mình thống trị. Lão nổi tiếng tâm ngoan thủ lạt nên không tu sĩ nào dám xâm phạm.","nguonGoc":"Do Xích Hỏa lão quái chiếm cứ","lanhDaoHienThoi":"Xích Hỏa lão quái","quyMo":"Một đảo do một người thống trị","trangThai":"hoat-dong","thanhVien":[{"ten":"Xích Hỏa lão quái","chucVu":"Đảo chủ (độc chiếm)","tuChuong":"@c0403","trangThai":"tai-vi"}],"tabs":{"tienTrinh":[{"chuong":"@c0403","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc khi Xích Hỏa lão quái tới trợ giúp Diệu Âm Môn","text":"Được các tu sĩ nhắc tới khi Xích Hỏa lão quái bay đến gia nhập liên minh.","anchor":"hắn độc chiếm cả Nguyên Quy đảo mà không người nào dám trêu chọc"}]},"nguon":["@c0403"]},{"id":"an-sat-mon","name":"Ẩn Sát Môn","aliases":["Ẩn Sát môn"],"type":"ta-phai","typeLabel":"Tà phái","diaBan":"Hải vực (tiểu đảo)","nhanVatChinh":["Môn chủ Ẩn Sát Môn"],"blurb":"Ẩn Sát Môn là một tông phái tà tu ít giao thiệp với bên ngoài, sở hữu lực lượng gồm ít nhất năm tu sĩ Kết Đan kỳ cùng khoảng năm mươi đệ tử Trúc Cơ kỳ, do một đại hán trung niên tu vi Kết Đan hậu kỳ làm môn chủ. Sào huyệt tạm thời trên một tiểu đảo của môn phái bị Diệu Âm Môn đột kích, khiến hơn nửa đệ tử Trúc Cơ kỳ bị diệt.","detail":"Ẩn Sát Môn là tông phái thuộc hàng tà tu, hoạt động kín đáo và rất ít lui tới với tu sĩ bên ngoài. Nguồn gốc cụ thể của môn phái không rõ ràng; đệ tử sử dụng Sát yêu biến thân thuật biến thể — một thuật pháp có hình thức tương tự nhưng khác biệt so với phiên bản của Hắc Sát Giáo, gợi lên nghi vấn về mối liên hệ giữa hai thế lực song chưa được xác nhận. Môn chủ là một đại hán trung niên tu vi Kết Đan hậu kỳ, dưới trướng có ít nhất năm tu sĩ Kết Đan kỳ và khoảng năm mươi đệ tử Trúc Cơ kỳ. Ẩn Sát Môn lập sào huyệt tạm thời trên một tiểu đảo, nhưng bị Diệu Âm Môn đột kích do bị giá họa. Trận chiến khiến môn phái mất hơn nửa số đệ tử Trúc Cơ kỳ. Môn chủ dẫn năm Kết Đan kỳ ứng chiến, đồng thời phủ nhận việc cướp hàng của Diệu Âm Môn và tuyên bố đệ tử bị giết vô cớ.","nguonGoc":"Không rõ, đệ tử dùng Sát yêu biến thân thuật biến thể có liên hệ nghi vấn với Hắc Sát Giáo","lanhDaoHienThoi":"Môn chủ Ẩn Sát Môn (đại hán trung niên Kết Đan hậu kỳ)","quyMo":"5 Kết Đan kỳ (1 hậu kỳ + 4 sơ kỳ), ~50 Trúc Cơ kỳ (trước trận đánh)","trangThai":"Suy yếu — mất hơn nửa đệ tử Trúc Cơ kỳ sau đột kích của Diệu Âm Môn","thanhVien":[{"ten":"Môn chủ Ẩn Sát Môn","chucVu":"Môn chủ","tuChuong":"@c0404","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0404","loai":"khai-chien","importance":"major","giaiDoan":"Bị Diệu Âm Môn đột kích sào huyệt","text":"Sào huyệt tạm thời trên tiểu đảo bị Diệu Âm Môn đột kích. Hơn nửa đệ tử Trúc Cơ kỳ bị diệt. Môn chủ dẫn năm Kết Đan kỳ nghênh chiến. Hai phe đối chất phát hiện bị giá họa.","anchor":"Ẩn Sát Môn chúng ta rất ít lui tới cùng tu sĩ bên ngoài, sao có thể làm ra loại sự tình này"}]},"capNhatToi":"@c0404","nguon":["@c0404","@c0454"],"cn":"隱殺門","dacDiem":"Tông phái tà tu hoạt động kín đáo, ít giao thiệp bên ngoài; đệ tử tu luyện Sát yêu biến thân thuật biến thể có liên hệ nghi vấn với Hắc Sát Giáo nhưng chưa xác nhận.","congNang":["Đệ tử Trúc Cơ kỳ sử dụng Sát yêu biến thân thuật biến thể — phiên bản khác với thuật pháp cùng tên của Hắc Sát Giáo @c0404"]},{"id":"hong-nguyet-dao","name":"Hồng Nguyệt đảo","cn":"","type":"dao","typeLabel":"Đảo","diaBan":"Loạn Tinh Hải","nhanVatChinh":["Thạch chân nhân","Thạch Điệp"],"blurb":"Thế lực trên Loạn Tinh Hải do Thạch chân nhân đứng đầu. Thạch Điệp (con gái chủ đảo) là cao thủ trận pháp đại danh đỉnh đỉnh của đảo.","detail":"Hồng Nguyệt đảo là một thế lực trên Loạn Tinh Hải. Thạch chân nhân là chủ đảo, từng có ân với Kim Thanh. Con gái ông là Thạch Điệp nổi tiếng về trận pháp, được mời tham gia phá đại trận phong ấn cổ tu sĩ.","lanhDaoHienThoi":"Thạch chân nhân","thanhVien":[{"ten":"Thạch chân nhân","chucVu":"Chủ đảo","tuChuong":"@c0416","trangThai":"dang-hoat-dong"},{"ten":"Thạch Điệp","chucVu":"Con gái chủ đảo, cao thủ trận pháp","tuChuong":"@c0416","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0416","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc khi giới thiệu Thạch Điệp","trangThaiMoc":"Hoạt động","text":"Thạch Điệp được giới thiệu là cao thủ trận pháp đại danh đỉnh đỉnh của Hồng Nguyệt đảo, con gái Thạch chân nhân. Thạch chân nhân từng có ân với Kim Thanh.","anchor":"Thạch tiên tử chính là cao thủ trận pháp đại danh đỉnh đỉnh của Hồng Nguyệt đảo"}]},"nguon":["@c0416"]},{"id":"doc-long-hoi","name":"Độc Long hội","cn":"毒龙会","type":"ta-dao","typeLabel":"Tổ chức tà đạo","diaBan":"Loạn Tinh Hải","nhanVatChinh":[],"blurb":"Tổ chức tu sĩ tà đạo, đại địch của Diệu Âm môn. Tu sĩ của hội mang đặc điểm toàn thân tà khí.","detail":"Tổ chức tà đạo hoạt động tại vùng Loạn Tinh Hải, là kẻ thù truyền kiếp của Diệu Âm môn. Ba tu sĩ Trúc Cơ sơ kỳ mặc cẩm y toàn thân tà khí thuộc hội này đang truy đánh đệ tử Diệu Âm môn.","nguon":["@c0429","@c0430"],"tabs":{"tienTrinh":[{"chuong":"@c0429","loai":"nhắc tới","importance":"normal","giaiDoan":"Giao chiến với đệ tử Diệu Âm môn","text":"Ba tu sĩ Trúc Cơ sơ kỳ cẩm y toàn thân tà khí thuộc Độc Long hội truy đánh đôi nam nữ đệ tử Diệu Âm môn, bị Hàn Lập bắt gặp.","anchor":"Ba người này là tu sĩ Độc Long hội – đại địch của bổn môn"},{"chuong":"@c0430","loai":"khai chien","importance":"normal","giaiDoan":"Truy đuổi cha con Văn Tường","text":"Ba tu sĩ Trúc Cơ kỳ chặn đường cha con Văn Tường hộ tống hàng hóa Diệu Âm Môn qua lãnh địa, bị Hàn Lập dùng Thanh Nguyên kiếm quang tiêu diệt gọn.","anchor":"đi qua lãnh địa Độc Long hội – kẻ tử địch của Diệu Âm môn"}]},"trangThai":"Đang hoạt động"},{"id":"nam-hac-dao","name":"Nam Hạc đảo","cn":"","type":"dao","typeLabel":"Đảo","diaBan":"Không rõ","nhanVatChinh":["Thanh Dịch cư sĩ"],"blurb":"Thế lực nơi lão nho sinh Nguyên Anh kỳ (Thanh Dịch cư sĩ) xuất thân.","detail":"Nơi xuất thân của lão nho sinh lông mày trắng Nguyên Anh kỳ được Cực Âm tổ sư gọi là Thanh huynh.","nguon":["@c0432"]},{"id":"bach-bich-son","name":"Bạch Bích sơn","cn":"","type":"mon-phai","typeLabel":"Môn phái","diaBan":"Không rõ","nhanVatChinh":["Ôn phu nhân"],"blurb":"Thế lực nơi Ôn phu nhân (Nguyên Anh kỳ) xuất thân.","detail":"Nơi xuất thân của Ôn phu nhân, mỹ phụ áo trắng tu vi Nguyên Anh kỳ, toàn thân tản hàn khí thấu xương.","nguon":["@c0432"]},{"id":"van-phap-mon","name":"Vạn Pháp môn","cn":"萬法門","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Loạn Tinh hải","nhanVatChinh":["Vạn Thiên Minh","Phong Bà Tử"],"blurb":"Tông môn chính đạo ở Loạn Tinh hải, do Vạn Thiên Minh làm môn chủ. Vạn Thiên Minh là nhân vật đầu lĩnh số một số hai của chính đạo.","detail":"Tông môn chính đạo có vị trí hàng đầu tại Loạn Tinh hải. Môn chủ Vạn Thiên Minh được coi là nhân vật đầu lĩnh số một số hai của chính đạo, tu vi cao đến mức Cực Âm tổ sư (Nguyên Anh sơ kỳ) cũng kiêng sợ.","lanhDaoHienThoi":"Vạn Thiên Minh","trangThai":"hưng thịnh","thanhVien":[{"ten":"Vạn Thiên Minh","chucVu":"Môn chủ","tuChuong":"@c0434","trangThai":"tai-vi"},{"ten":"Phong Bà Tử","chucVu":"Nhân vật quan trọng","tuChuong":"@c0463","trangThai":""}],"tabs":{"tienTrinh":[{"chuong":"@c0434","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu được nhắc tới","trangThaiMoc":"hưng thịnh","text":"Vạn Pháp môn được nhắc tới khi môn chủ Vạn Thiên Minh xuất hiện tại đại sảnh, nhân vật đầu lĩnh chính đạo Loạn Tinh hải.","anchor":"chỉ có thể lờ mờ nghe được có người thấp giọng nói “Vạn Pháp môn môn chủ” gì gì đó"},{"chuong":"@c0463","loai":"nhắc tới","importance":"normal","giaiDoan":"Lần đầu được nhắc tên","text":"Hai trưởng lão Tinh Cung nhắc tới Vạn Pháp Môn Phong Bà Tử như thế lực đối đầu Tinh Cung, phải tránh lui trước Nguyên Từ Thần Quang.","anchor":"Vạn Pháp Môn Phong Bà Tử và Thánh ma đạo lục đảo","trangThaiMoc":"đang hoạt động"}]},"nguon":["@c0434","@c0463"],"aliases":["Vạn Pháp môn"]},{"id":"thien-thai-dao","name":"Thiên Thai Đảo","cn":"","type":"dao-dao","typeLabel":"Đảo","diaBan":"Loạn Tinh Hải","nhanVatChinh":["Cát Lạp"],"blurb":"Thế lực tại Loạn Tinh Hải, nơi lão giả Cát Lạp xuất thân. Lần đầu được nhắc tên khi Cát Lạp tự giới thiệu trong Hư Thiên Điện.","detail":"Thiên Thai Đảo là một thế lực ở Loạn Tinh Hải. Tu sĩ Kết đan kỳ Cát Lạp tự xưng đến từ đảo này khi đề nghị liên thủ với Hàn Lập và Tử Linh để vượt qua vùng quỷ vụ trong Hư Thiên Điện.","thanhVien":[{"ten":"Cát Lạp","chucVu":"Thành viên","tuChuong":"@c0437","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0437","loai":"nhắc tới","importance":"normal","giaiDoan":"Lần đầu nhắc tên","text":"Cát Lạp tự xưng đến từ Thiên Thai Đảo khi gặp Hàn Lập và Tử Linh trong Hư Thiên Điện.","anchor":"Tại hạ là Thiên Thai Đảo Cát Lạp"}]},"nguon":["@c0437"]},{"id":"thanh-duong-mon","name":"Thanh Dương Môn","cn":"","type":"ma-dao","typeLabel":"Thế lực ma đạo","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Thế lực ma đạo bí chế ra Thanh Hỏa Lôi, loại bảo bối tiêu hao có uy lực tương đương nguyên dương hỏa Nguyên Anh kỳ.","detail":"Được nhắc tới là nơi bí chế Thanh Hỏa Lôi với nguyên liệu quý hiếm và thời gian luyện chế lâu.","nguon":["@c0462"]},{"id":"thanh-ma-dao","name":"Thánh ma đạo","cn":"圣魔道","aliases":["Thánh ma đạo lục đảo"],"type":"lien-minh","typeLabel":"Liên minh","diaBan":"Loạn Tinh Hải","nhanVatChinh":[],"blurb":"Thế lực ma đạo gồm sáu đảo tại Loạn Tinh Hải, cùng Vạn Pháp Môn là các bên mà Tinh Cung lo ngại liên thủ.","detail":"Được hai trưởng lão Tinh Cung nhắc tên cùng Vạn Pháp Môn. Có quy mô sáu đảo. Cùng là thế lực phải tránh lui trước Nguyên Từ Thần Quang của thánh chủ Tinh Cung.","quyMo":"Sáu đảo","tabs":{"tienTrinh":[{"chuong":"@c0463","loai":"nhắc tới","importance":"normal","giaiDoan":"Lần đầu được nhắc tên","text":"Hai trưởng lão Tinh Cung nhắc tới Thánh ma đạo lục đảo cùng Vạn Pháp Môn như các thế lực mà Tinh Cung phải đề phòng.","anchor":"Vạn Pháp Môn Phong Bà Tử và Thánh ma đạo lục đảo","trangThaiMoc":"đang hoạt động"}]},"nguon":["@c0463"]},{"id":"thien-co-mon","name":"Thiên Cơ môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":[],"blurb":"Tông môn được nhắc tới qua lời Vạn Thiên Minh, nhóm chính đạo đã mượn vật của Thiên Cơ môn để tránh né Khôi lỗi thủ vệ trong nội điện.","detail":"Thiên Cơ môn lần đầu được nhắc đến khi Vạn Thiên Minh cho biết nhóm chính đạo ba người đã mượn vật phẩm của tông môn này để tránh né Khôi lỗi thủ vệ bên trong nội điện Hư Thiên Điện, nhờ đó vượt qua an toàn mà không cần giao chiến.","tabs":{"tienTrinh":[{"chuong":"@c0475","loai":"nhắc tới","importance":"normal","giaiDoan":"Lần đầu được nhắc tên","text":"Vạn Thiên Minh cho biết nhóm chính đạo mượn vật của Thiên Cơ môn để tránh né Khôi lỗi thủ vệ.","anchor":"Tuy lần này mượn vật của Thiên Cơn môn tránh né được những Khôi lỗi thủ vệ kia"}]},"nguon":["@c0475"]},{"id":"tam-tinh-tong","name":"Tam Tinh tông","cn":"三星宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Loạn Tinh hải","nhanVatChinh":["Lão giả tóc xám trắng (Tam Tinh tông)","Tuyết Địch tiên tử"],"blurb":"Tông môn ở Loạn Tinh hải, phái đội tu sĩ Trúc Cơ kỳ đến Thiên Tinh thành khi nơi đó xảy ra đại sự.","detail":"Tông môn có tu sĩ Trúc Cơ kỳ hoạt động ở vùng Loạn Tinh hải. Khi Thiên Tinh thành xảy ra đại sự, tông chủ lập tức phái đội bảy tám người do lão giả tóc xám trắng dẫn đầu đến đó.","thanhVien":[{"ten":"Lão giả tóc xám trắng (Tam Tinh tông)","chucVu":"Tu sĩ","tuChuong":"@c0497","trangThai":"tai-chuc"},{"ten":"Tuyết Địch tiên tử","chucVu":"Tiên tử","tuChuong":"@c0498","trangThai":"tai-chuc"}],"tabs":{"tienTrinh":[{"chuong":"@c0497","loai":"nhắc tới","importance":"bridge","giaiDoan":"Phái người đi Thiên Tinh thành","text":"Tông chủ phái đội bảy tám tu sĩ Trúc Cơ kỳ đến Thiên Tinh thành vì đại sự.","anchor":"Bọn vãn bối là tu sĩ thuộc Tam Tinh tông phụng mệnh tông chủ đi đến Thiên Tinh thành"},{"chuong":"@c0498","loai":"nhắc tới","importance":"normal","giaiDoan":"Cử người quan sát chiến sự","trangThaiMoc":"Trung lập","text":"Tam Tinh tông cử nhóm tu sĩ đến phụ cận Thiên Tinh thành quan sát tình hình đại chiến Tinh Cung – Nghịch Tinh minh trước khi quyết định lập trường.","anchor":"Tuyết Địch tiên tử của bản tông cùng Tử Linh tiên tử của quý tông là bạn bè thân thiết"}]},"nguon":["@c0497","@c0498"],"trangThai":"Trung lập, đang quan sát"},{"id":"nghich-tinh-minh","name":"Nghịch Tinh minh","cn":"逆星盟","aliases":["Nghịch Minh Tinh"],"type":"lien-minh","typeLabel":"Liên minh","diaBan":"Loạn Tinh Hải","nhanVatChinh":["Vạn Tam Cô","Lục đạo cực thánh","Ôn Thiên Nhân","Lục Đạo"],"blurb":"Nghịch Tinh Minh là liên minh do Chính đạo và Ma đạo liên thủ thành lập nhằm đánh đổ bá quyền Tinh Cung tại Loạn Tinh Hải, do Vạn Tam Cô và Lục đạo cực thánh đồng đứng đầu. Sau khi khai chiến với Tinh Cung, thế lực này hùng cứ nửa Loạn Tinh Hải, đủ sức khiến các tu sĩ Kết Đan kỳ phải kiêng dè rút lui chỉ khi nghe danh.","detail":"Sau khi Tinh Cung phát Thiên Tinh lệnh triệu tập cưỡng chế, Chính đạo và Ma đạo chính thức tuyên bố liên thủ thành lập Nghịch Tinh Minh (@c0498). Nhiều tông môn, thế lực gia nhập, một số tán tu Nguyên Anh kỳ đảm nhận chức trưởng lão. Nghịch Tinh Minh phát Nghịch Tinh lệnh — một loại quỷ bài — đe dọa bất kỳ ai phục tùng Tinh Cung sẽ trở thành kẻ thù. Liên minh phát động tấn công các ngoại đảo Thiên Tinh thành và chiếm thế thượng phong, một số đảo trực tiếp tuyên bố quy thuận. Đến giai đoạn khai chiến quyết liệt, Truyền tống trận bị phong tỏa chỉ cho ra không cho vào (@c0522). Về nhân sự, Ôn Thiên Nhân được xác nhận là Thiếu chủ Nghịch Tinh Minh, đồng thời là ma đạo đệ nhất truyền nhân, sở hữu nhiều bảo vật (@c0572). Danh tiếng của Nghịch Tinh Minh đủ sức khiến hai tu sĩ Kết Đan kỳ thuộc Hoà","nguonGoc":"Chính đạo và Ma đạo liên thủ đối kháng Tinh Cung sau khi Thiên Tinh lệnh ban hành","lanhDaoHienThoi":"Vạn Tam Cô (Chính đạo) và Lục đạo cực thánh (Ma đạo)","trangThai":"Đang giao chiến với Tinh Cung","thanhVien":[{"ten":"Vạn Tam Cô","chucVu":"Đồng minh chủ (đại diện Chính đạo)","tuChuong":"@c0498","trangThai":"tai-chuc"},{"ten":"Lục đạo cực thánh","chucVu":"Đồng minh chủ (đại diện Ma đạo)","tuChuong":"@c0498","trangThai":"tai-chuc"},{"ten":"Ôn Thiên Nhân","chucVu":"Thiếu chủ","tuChuong":"@c0572","trangThai":"dang-hoat-dong"}],"lanhDaoMoc":[{"ten":"Vạn Tam Cô","tuChuong":"@c0498","denChuong":""},{"ten":"Lục đạo cực thánh","tuChuong":"@c0498","denChuong":""}],"tabs":{"tienTrinh":[{"chuong":"@c0498","loai":"lập","importance":"major","giaiDoan":"Thành lập liên minh Chính Ma chống Tinh Cung","trangThaiMoc":"Hưng thịnh","text":"Chính đạo và Ma đạo tuyên bố liên thủ thành lập Nghịch Tinh minh nhằm đánh đổ bá quyền Tinh Cung. Vạn Tam Cô và Lục đạo cực thánh đồng đứng đầu. Phát Nghịch Tinh lệnh đe dọa các thế lực, đồng thời phát động tấn công ngoại đảo Thiên Tinh thành và chiếm thế thượng phong.","anchor":"chính đạo và ma đạo đột nhiên tuyên bố liên thủ thành lập một tổ chức gọi là “Nghịch Tinh minh”"},{"chuong":"@c0522","loai":"khai chiến","importance":"major","trangThaiMoc":"Đang giao chiến","giaiDoan":"Đại chiến với Tinh Cung","text":"Nghịch Tinh Minh và Tinh Cung đang đánh nhau quyết liệt, Truyền tống trận bị phong tỏa chỉ cho ra không cho vào.","anchor":"Tinh Cung và Nghịch Tinh Minh bên kia đang đánh nhau quyết liệt"},{"chuong":"@c0572","loai":"nhắc tới","importance":"normal","giaiDoan":"Xác nhận thân phận Thiếu chủ","text":"Ôn Thiên Nhân được xác nhận là Thiếu chủ Nghịch Tinh Minh, ma đạo đệ nhất truyền nhân, sở hữu nhiều bảo vật.","anchor":"Dù sao đối phương với thân phận là Thiếu chủ của Nghịc Tinh Minh, ma đạo đệ nhất truyền nhân"},{"chuong":"@c0574","loai":"nhắc tới","importance":"normal","giaiDoan":"Uy danh lan rộng","text":"Danh tiếng Nghịch Tinh Minh khiến hai tu sĩ Kết Đan kỳ Hoàng Minh Đảo hoảng sợ rút lui ngay khi nghe thân phận Ôn Thiên Nhân là Lục Đạo Truyền Nhân.","anchor":"đối mặt với ma đạo đệ nhất nhân cùng với Nghịch Tinh Minh thế lực ngập trời của Lục Đạo Cực Thánh này"},{"chuong":"@c0575","loai":"nhắc tới","importance":"normal","giaiDoan":"Ôn Thiên Nhân dùng danh nghĩa Nghịch Tinh Minh đe dọa","text":"Ôn Thiên Nhân dùng quyền lực Nghịch Tinh Minh hùng cứ nửa Loạn Tinh Hải để uy hiếp Tử Linh Tiên Tử phải đi bắt Nguyên Dao.","anchor":"Bổn minh bây giờ hùng cứ một nửa Loạn Tinh Hải"}]},"capNhatToi":"@c0498","nguon":["@c0498","@c0522","@c0572","@c0574","@c0575"],"uyLuc":"Hùng cứ nửa Loạn Tinh Hải, danh tiếng đủ khiến tu sĩ Kết Đan kỳ hoảng sợ rút lui ngay khi nghe đến tên (@c0574).","dacDiem":"Liên minh xuyên lập trường Chính–Ma, lấy mục tiêu chung là lật đổ bá quyền Tinh Cung làm chất kết dính; do Vạn Tam Cô và Lục đạo cực thánh đồng đứng đầu, có cả tán tu Nguyên Anh kỳ giữ chức trưởng lão.","congNang":["Phát Nghịch Tinh lệnh (quỷ bài) đe dọa các thế lực phục tùng Tinh Cung sẽ trở thành kẻ thù (@c0498)","Phát động tấn công các ngoại đảo Thiên Tinh thành, chiếm thế thượng phong, buộc một số đảo tuyên bố quy thuận (@c0498)","Phong tỏa Truyền tống trận trong giai đoạn khai chiến với Tinh Cung, chỉ cho ra không cho vào (@c0522)","Quyền lực liên minh đủ để hùng cứ nửa Loạn Tinh Hải, dùng uy thế uy hiếp tu sĩ các phương (@c0575)"]},{"id":"khai-thien-mon","name":"Khai Thiên Môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Loạn Tinh Hải","nhanVatChinh":["Tân Minh"],"blurb":"Môn phái tại Loạn Tinh Hải, môn chủ từng có giao tình với hộ pháp Nghịch Minh Tinh Thương Vân Long.","detail":"Môn phái hoạt động tại vùng Loạn Tinh Hải. Đệ tử Tân Minh dùng Bạch Thủy Kiếm làm tín vật chứng minh thân phận trong cuộc bàn tra của Nghịch Minh Tinh tại Nam Minh đảo.","nguon":["@c0500"]},{"id":"the-luc-thong-tri-ky-uyen-dao","name":"Thế lực thống trị Kỳ Uyên Đảo","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Kỳ Uyên Đảo","nhanVatChinh":[],"blurb":"Thế lực cường đại bí ẩn thống trị Kỳ Uyên Đảo, kiểm soát nghiêm ngặt mọi thông tin ra vào đảo, khiến ngay cả Tinh Cung cũng không dám đắc tội. Mọi tu sĩ rời đảo đều bị ép tiết lộ cùng một loại tin tức ngụy tạo thống nhất.","detail":"Theo lời Hứa Vân tiết lộ tại @c0510, Kỳ Uyên Đảo nằm dưới sự thống trị của một thế lực cường đại mà lai lịch chưa được làm rõ. Thế lực này áp đặt sự kiểm soát thông tin cực kỳ nghiêm ngặt: tất cả tu sĩ trở về từ đảo đều bị ép phải tiết lộ cùng một bộ tin tức giả, nhằm ngăn chặn bất kỳ thông tin thực sự nào về nội tình của đảo lọt ra ngoài. Trên đảo chỉ có duy nhất một tòa thành là Hắc Thạch thành, nơi nghiêm cấm đấu pháp; kẻ vi phạm sẽ bị hình thần câu diệt, chưa từng có ai phạm quy mà sống sót trốn khỏi thành. Hắc Thạch thành luôn có tu sĩ Nguyên Anh Kỳ tọa trấn, cho thấy thực lực của thế lực này ít nhất ở tầng Nguyên Anh trở lên. Ngay cả Tinh Cung — một thế lực lớn — cũng không dám đắc tội, phản ánh uy thế vượt trội của thế lực thống trị này trong khu vực.","nguonGoc":"Chưa rõ","lanhDaoHienThoi":"Chưa rõ","quyMo":"Cực lớn, Tinh Cung không dám đắc tội","caoThuManhNhat":"Có tu sĩ Nguyên Anh Kỳ tọa trấn","trangThai":"hưng","capNhatToi":"@c0510","tabs":{"tienTrinh":[{"chuong":"@c0510","loai":"nhắc tới","importance":"major","giaiDoan":"Lần đầu hé lộ sự tồn tại","text":"Hứa Vân tiết lộ Kỳ Uyên Đảo bị thế lực cường đại thống trị, Tinh Cung cũng không dám đắc tội. Thế lực này ép mọi tu sĩ rời đảo chỉ tiết lộ tin tức ngụy tạo thống nhất, luôn có tu sĩ Nguyên Anh Kỳ tọa trấn Hắc Thạch thành.","anchor":"nơi này đích xác bị một thế lực cường đại thống trị, lực lượng của thế lực này cho dù là Tinh Cung cũng không dễ dàng đắc tội"}]},"nguon":["@c0510"],"uyLuc":"Khiến ngay cả Tinh Cung cũng không dám đắc tội; trong Hắc Thạch thành, kẻ vi phạm lệnh cấm sẽ bị hình thần câu diệt, chưa từng có ai phạm quy mà sống sót trốn khỏi thành @c0510.","dacDiem":"Bí ẩn, không rõ lai lịch; thống trị toàn bộ Kỳ Uyên Đảo với chế độ kiểm soát thông tin tuyệt đối, chỉ cho phép một tòa thành duy nhất — Hắc Thạch thành — tồn tại trên đảo.","congNang":["Kiểm soát thông tin toàn diện: ép tất cả tu sĩ rời Kỳ Uyên Đảo chỉ được tiết lộ cùng một bộ tin tức ngụy tạo thống nhất @c0510","Hình thần câu diệt: trừng phạt kẻ vi phạm lệnh cấm đấu pháp trong Hắc Thạch thành, hủy diệt cả hình hài lẫn thần hồn, chưa ai vi phạm mà thoát chết @c0510","Luôn duy trì tu sĩ Nguyên Anh Kỳ tọa trấn Hắc Thạch thành @c0510"]},{"id":"minh-chau-hien","name":"Minh Châu hiên","cn":"","type":"thuong-hoi","typeLabel":"Thương hội / Cơ sở kinh doanh","diaBan":"Kỳ Uyên đảo","nhanVatChinh":["Minh phu nhân"],"blurb":"Cơ sở chuyên mua thu vật phẩm của tu sĩ hải ngoại trên Kỳ Uyên đảo, đổi linh thạch hoặc đấu giá. Có tu sĩ Nguyên Anh Kỳ chống lưng.","detail":"Bên trong chia hai đại sảnh: Giám Bảo thính (giám định, đổi đồ lấy linh thạch) và Bảo thính (phòng đấu giá, phàm nhân không được vào). Minh phu nhân là người quản lý. Mỗi cơ sở kinh doanh kiểu này trên các Yêu Thú đảo đều có tu sĩ Nguyên Anh Kỳ chống lưng.","nguonGoc":"Cơ sở kinh doanh trên Kỳ Uyên đảo phục vụ tu sĩ hải ngoại","lanhDaoHienThoi":"Minh phu nhân","trangThai":"hung","thanhVien":[{"ten":"Minh phu nhân","chucVu":"Quản lý","tuChuong":"@c0511","trangThai":"dang-nhiem"}],"tabs":{"tienTrinh":[{"chuong":"@c0511","loai":"xuat-hien","importance":"normal","giaiDoan":"Giới thiệu","text":"Nhóm Hàn Lập theo Hứa Vân vào Minh Châu hiên, nơi chuyên mua thu vật phẩm tu sĩ hải ngoại, bên trong chia Giám Bảo thính và Bảo thính.","anchor":"là nơi chuyên môn mua thu của các tu sĩ tại hải ngoại, đem đổi thành linh thạch hoặc kiểm tra đồ vật trân quý"}]},"capNhatToi":"@c0511","nguon":["@c0511"]},{"id":"lien-minh-ky-uyen-dao","name":"Liên minh thế lực Kỳ Uyên đảo","cn":"","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Kỳ Uyên đảo","nhanVatChinh":[],"blurb":"Nhiều thế lực có cao nhân Nguyên Anh Kỳ liên thủ khống chế Kỳ Uyên đảo, đây là Yêu Thú đảo duy nhất không bị tứ đại thương minh lũng đoạn.","detail":"Các thế lực liên thủ quản lý Kỳ Uyên đảo sau cuộc đại chiến với tứ đại thương minh, được Tinh Cung hòa giải. Mỗi thế lực đều có tu sĩ Nguyên Anh Kỳ chống lưng. Nghiêm cấm tiết lộ tình hình thật của đảo ra Nội Tinh Hải, ai vi phạm sẽ bị liên thủ đuổi giết diệt khẩu.","trangThai":"hung","tabs":{"tienTrinh":[{"chuong":"@c0511","loai":"xuat-hien","importance":"normal","giaiDoan":"Giới thiệu liên minh","text":"Kỳ Uyên đảo là nơi duy nhất do nhiều thế lực liên thủ khống chế, không bị tứ đại thương minh lũng đoạn, mỗi thế lực có Nguyên Anh Kỳ chống lưng.","anchor":"là nơi duy nhất hoàn toàn do nhiều thế lực liên thủ khống chế Yêu Thú đảo"}]},"capNhatToi":"@c0511","nguon":["@c0511"]},{"id":"thon-kim-cac","name":"Thốn Kim Các","cn":"","type":"thuong-hoi","typeLabel":"Thương hội","diaBan":"Hắc Thạch thành","nhanVatChinh":["Ly Tầm","Cổ Ngọc"],"blurb":"Cửa hàng nguyên liệu lớn nhất Hắc Thạch thành, nổi tiếng có đủ mọi loại nguyên liệu trân quý. Có mạng lưới tình báo nhanh nhạy qua Truyền tấn phù.","detail":"Bề ngoài là nhà đá to lớn, bên trong chia nhiều gian nhỏ chuyên bán các loại nguyên liệu khác nhau, có gian khách quý riêng tiếp tu sĩ Kết Đan trở lên. Quản sự hiện tại là Ly Tầm (Kết Đan sơ kỳ). Có chuyên gia nghiên cứu nguyên liệu thời thượng cổ (Cổ Ngọc, Luyện Khí kỳ). Sở hữu mạng lưới Truyền tấn phù tra nhanh lai lịch khách hàng.","nguonGoc":"","lanhDaoHienThoi":"Ly Tầm (quản sự)","quyMo":"Cửa hàng nguyên liệu lớn nhất Hắc Thạch thành","trangThai":"hoat-dong","thanhVien":[{"ten":"Ly Tầm","chucVu":"Quản sự","tuChuong":"@c0513","trangThai":"dang-nhiem"},{"ten":"Cổ Ngọc","chucVu":"Chuyên gia nguyên liệu thượng cổ","tuChuong":"@c0513","trangThai":"dang-nhiem"}],"tabs":{"tienTrinh":[{"chuong":"@c0513","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập lần đầu ghé thăm","text":"Hàn Lập vào Thốn Kim Các tìm mua linh dược thượng cổ, được quản sự Ly Tầm tiếp đón trọng thị và gọi chuyên gia Cổ Ngọc hỗ trợ.","anchor":"chuyên môn bán ra các loại nguyên liệu trân quý"}]},"capNhatToi":"@c0513","nguon":["@c0513"]},{"id":"bo-toc-giao-long","name":"Bộ tộc Giao Long","cn":"蛟龙部族","type":"yeu-thu","typeLabel":"Thế lực yêu thú","diaBan":"Loạn Tinh Hải","nhanVatChinh":[],"blurb":"Bộ tộc Giao Long là một bộ tộc yêu thú bản địa cư ngụ tại Loạn Tinh Hải, bị chọc giận bởi trận đại chiến giữa tu sĩ Nguyên Anh kỳ và cự quy, sau đó tham gia phe yêu thú cấp cao đồ sát tu sĩ nhân loại, gây tổn thất rất lớn cho phe tu sĩ.","detail":"Bộ tộc Giao Long là thế lực yêu thú bản địa tại Loạn Tinh Hải. Sau khi trận đại chiến giữa tu sĩ Nguyên Anh kỳ và cự quy trên hoang đảo sương mù nổ ra, bộ tộc Giao Long bị chọc giận và gia nhập trận tuyến yêu thú cấp cao. Họ tiến hành đồ sát tu sĩ nhân loại trong khu vực, gây ra tổn thất rất lớn cho phe tu sĩ. Sự tham chiến của bộ tộc Giao Long đánh dấu bước leo thang nghiêm trọng của xung đột giữa yêu thú và nhân loại tại Loạn Tinh Hải.","nguonGoc":"Bộ tộc yêu thú bản địa Loạn Tinh Hải","trangThai":"hoat-dong","tabs":{"tienTrinh":[{"chuong":"@c0520","loai":"khai chiến","importance":"major","giaiDoan":"Tham gia đại chiến yêu thú vs tu sĩ","trangThaiMoc":"Bị chọc giận, gia nhập phe yêu thú","text":"Bộ tộc Giao Long ở Loạn Tinh Hải bị chọc giận bởi trận đại chiến, tham gia vào trận tuyến yêu thú cấp cao đồ sát tu sĩ nhân loại, gây tổn thất rất lớn cho phe tu sĩ.","anchor":"Bộ tộc Giao Long ở Loạn Tinh Hải bị chọc giận, cũng tham gia vào trận tuyến yêu thú cấp cao đồ sát tu sĩ nhân loại"}]},"nguon":["@c0520"]},{"id":"bich-van-mon","name":"Bích Vân Môn","cn":"碧云门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Kỳ Uyên Đảo","nhanVatChinh":["Diệu Hạc chân nhân"],"blurb":"Bích Vân Môn là một trong năm thế lực lớn của Kỳ Uyên Đảo. Sau trận giao tranh với Trùng Ma (Hàn Lập) vì tranh đoạt yêu thú cấp bảy, môn phái mất bảy tám tu sĩ Kết Đan kỳ, tổn thất gần một phần ba lực lượng, thực lực suy giảm nghiêm trọng.","detail":"Bích Vân Môn từng là một trong năm thế lực lớn nhất trên Kỳ Uyên Đảo. Bốn năm trước thời điểm được nhắc đến, vì tranh đoạt yêu thú cấp bảy, Trùng Ma một mình tiêu diệt bảy tám tu sĩ Kết Đan kỳ của môn phái, chỉ một tu sĩ Kết Đan hậu kỳ may mắn chạy thoát. Trận chiến khiến Bích Vân Môn tổn thất gần một phần ba lực lượng, thực lực suy giảm nghiêm trọng. Thái thượng Trưởng lão Diệu Hạc chân nhân tức giận đích thân xuất hải truy tìm Trùng Ma nhưng biệt vô âm tín, không trở về.","nguonGoc":"","lanhDaoHienThoi":"Diệu Hạc chân nhân (Thái thượng Trưởng lão, đã mất tích)","quyMo":"Một trong năm thế lực lớn Kỳ Uyên Đảo","trangThai":"suy","thanhVien":[{"ten":"Diệu Hạc chân nhân","chucVu":"Thái thượng Trưởng lão","tuChuong":"@c0523","trangThai":"mat-tich"}],"tabs":{"tienTrinh":[{"chuong":"@c0523","loai":"suy","importance":"major","giaiDoan":"Bị Trùng Ma tiêu diệt bảy tám tu sĩ Kết Đan","trangThaiMoc":"suy","text":"Bảy tám tu sĩ Kết Đan kỳ bị Trùng Ma tiêu diệt trong trận tranh yêu thú cấp bảy, mất gần một phần ba lực lượng. Thái thượng Trưởng lão Diệu Hạc chân nhân xuất hải truy tìm Trùng Ma nhưng biệt vô âm tín.","anchor":"Trận chiến này làm cho Bích Vân Môn được xưng là một trong năm thế lực lớn của Kỳ Uyên Đảo bị tổn thất gần một phần ba lực lượng"}]},"nguon":["@c0523","@c0556"]},{"id":"thanh-linh-mon","name":"Thanh Linh Môn","cn":"青灵门","type":"mon-phai","typeLabel":"Môn phái","diaBan":"Vùng biển (khu vực Ngoại Tinh hải)","nhanVatChinh":["Trung niên tu sĩ Thanh Linh Môn"],"blurb":"Môn phái nhỏ, trưởng lão Kết Đan kỳ duy nhất đã mất mạng trong thú triều hơn hai mươi năm trước. Hiện tu sĩ Trúc Cơ kỳ cũng không còn mấy người, đệ tử phải tự ra biển hái linh dược.","detail":"Thanh Linh Môn là một môn phái nhỏ. Trước kia có một vị trưởng lão Kết Đan kỳ nhưng đã tử vong trong sự kiện thú triều hơn hai mươi năm trước. Hiện tại trong môn không còn mấy tu sĩ Trúc Cơ kỳ, đệ tử Luyện Khí kỳ phải tự tổ chức nhóm nhỏ ra biển hái linh dược mà không có trưởng bối hộ tống.","nguonGoc":"","quyMo":"Môn phái nhỏ","trangThai":"Suy yếu nghiêm trọng sau thú triều","thanhVien":[{"ten":"Trung niên tu sĩ Thanh Linh Môn","chucVu":"Đệ tử (dẫn nhóm)","tuChuong":"@c0528","trangThai":"song"},{"ten":"Nữ tu sĩ cẩm y lam (Thanh Linh Môn)","chucVu":"Đệ tử","tuChuong":"@c0528","trangThai":"song"}],"tabs":{"tienTrinh":[{"chuong":"@c0528","loai":"nhắc tới","importance":"normal","giaiDoan":"Tiết lộ tình trạng suy yếu","text":"Trung niên tu sĩ tiết lộ Thanh Linh Môn là môn phái nhỏ, trưởng lão Kết Đan kỳ duy nhất đã mất mạng trong thú triều hơn hai mươi năm trước, hiện tu sĩ Trúc Cơ kỳ cũng không còn mấy người.","anchor":"Thanh Linh Môn chúng ta chính là một môn phái nhỏ, trước kia mặc dù cũng có một vị trưởng lão Kết Đan Kỳ, nhưng hơn hai mươi năm trước đã mất mạng trong thú triều"}]},"nguon":["@c0528"]},{"id":"phuong-thi-bi-an-dao-nho","name":"Phường thị bí ẩn (đảo nhỏ)","cn":"","type":"cho-den","typeLabel":"Chợ ngầm","diaBan":"Đảo nhỏ hướng đông ngoài hải vực","nhanVatChinh":[],"blurb":"Chợ ngầm dưới lòng đảo nhỏ ngoài hải vực, do một Hội chủ bí ẩn điều hành, có hai tầng giao dịch và Thính Phong các cung cấp tình báo. Định kỳ tổ chức Giao hoán hội riêng cho tu sĩ Kết Đan kỳ.","detail":"Phường thị nằm hoàn toàn dưới lòng đảo, sử dụng Thạch Hóa thuật tạo nên hang đá cao năm sáu trượng, cột đá xanh chống đỡ. Tầng trên có nhiều thạch ốc nhỏ bán hàng thường, hơn trăm tu sĩ giao dịch. Tầng dưới bán dược liệu trân quý và có Thính Phong các chuyên cung cấp tin tình báo về dị bảo và yêu thú cao giai. Không bố trí cấm chế trên mặt đảo để tránh thu hút yêu thú. Mỗi kỳ phường thị, Hội chủ tổ chức Giao hoán hội dành riêng cho tu sĩ Kết Đan kỳ, quy mô nhỏ, bắt đầu vào trung kỳ.","nguonGoc":"Do một Hội chủ bí ẩn lập, danh tính chưa rõ","quyMo":"Hơn trăm tu sĩ giao dịch thường kỳ","lanhDaoHienThoi":"Hội chủ (chưa rõ danh tính)","trangThai":"hoat-dong","capNhatToi":"@c0533","tabs":{"tienTrinh":[{"chuong":"@c0533","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập đến phường thị","text":"Hàn Lập cùng Hoàng Minh Lễ đến đảo, vào phường thị ngầm dưới lòng đảo. Tìm kiếm Bạn yêu thả và tin tức yêu thú cấp cao nhưng không được. Giao hoán hội dành cho tu sĩ Kết Đan kỳ sắp bắt đầu.","anchor":"loại đảo này bên ngoài hải vực đúng là có rất nhiều"}]},"nguon":["@c0533"]},{"id":"hai-toc","name":"Hải tộc","cn":"","type":"yeu-toc","typeLabel":"Yêu tộc","diaBan":"Hải vực phụ cận","nhanVatChinh":[],"blurb":"Thế lực yêu tộc đang khai chiến với tu sĩ nhân loại. Liệt Phong Thú xác nhận cuộc chiến là sự tình của hải tộc phụ cận, hắn không thuộc quản hạt của chúng.","detail":"Hải tộc phụ cận đang khai chiến với nhân loại. Liệt Phong Thú (yêu tộc cấp chín) tự nhận không thuộc quản hạt của hải tộc này, cho thấy yêu tộc không phải khối thống nhất mà có phân chia lãnh thổ và phe phái riêng.","tabs":{"tienTrinh":[{"chuong":"@c0540","loai":"khai chiến","importance":"normal","giaiDoan":"Đang khai chiến với nhân loại","text":"Liệt Phong Thú xác nhận cuộc chiến với nhân loại là sự tình của hải tộc phụ cận, hắn không thuộc quản hạt.","anchor":"Hiện tại khai chiến với nhân loại các ngươi chỉ là sự tình của hải tộc phụ cận"}]},"nguon":["@c0540"]},{"id":"bo-toc-liet-phong-thu","name":"Bộ tộc Liệt Phong Thú","cn":"烈风兽部族","type":"yeu-toc","typeLabel":"Bộ tộc yêu tu","diaBan":"Ngoại Tinh Hải","nhanVatChinh":["Phong Hi"],"blurb":"Bộ tộc yêu tu sở hữu thiên phú thần thông đặc thù, có thể luyện chế Bích Diễm Tửu — loại linh tửu giúp Kết Đan kỳ tu sĩ đột phá bình cảnh, các loài yêu tu khác không điều chế được.","detail":"Bộ tộc Liệt Phong Thú là một thế lực yêu tu tại vùng biển Ngoại Tinh Hải. Sở hữu thiên phú thần thông riêng biệt cho phép luyện chế Bích Diễm Tửu từ hóa hình giai yêu đan, phương pháp đặc thù mà các loài yêu tu khác không thể bắt chước. Phong Hi là thành viên cấp chín của bộ tộc.","dacDiem":"Có thiên phú thần thông riêng biệt luyện chế Bích Diễm Tửu","thanhVien":[{"ten":"Phong Hi","chucVu":"Thành viên cấp chín","tuChuong":"@c0541","trangThai":"hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0541","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến qua lời Phong Hi","text":"Phong Hi tự xưng thuộc bộ tộc Liệt Phong Thú, tiết lộ chỉ bộ tộc này có thiên phú thần thông đặc thù luyện chế Bích Diễm Tửu.","anchor":"chỉ có bộ tộc Liệt Phong Thú chúng ta mới có được phương pháp đặc thù, tạo ra loại rượu này"}]},"nguon":["@c0541"]},{"id":"thien-dia-linh-toc","name":"Thiên Địa Linh Tộc","cn":"天地灵族","type":"chung-toc","typeLabel":"Chủng tộc yêu thú","diaBan":"Hải vực","nhanVatChinh":["Độc Giao","Cự Quy"],"blurb":"Chủng tộc yêu thú thượng đẳng trong hải tộc. Thành viên dù chỉ ở giai đoạn hoá hình (cấp tám) cũng có bản lĩnh thần thông không yếu hơn yêu tu cấp chín bao nhiêu.","detail":"Phong Hi giới thiệu Độc Giao và Cự Quy thuộc Thiên Địa Linh Tộc, đứng hàng đầu hải tộc. Bản lĩnh thần thông chân chính của thành viên chủng tộc này không yếu hơn yêu tu cấp chín bao nhiêu dù chỉ ở giai đoạn hoá hình.","thanhVien":[{"ten":"Độc Giao","chucVu":"Thành viên","tuChuong":"@c0542","trangThai":"hoat-dong"},{"ten":"Cự Quy","chucVu":"Thành viên","tuChuong":"@c0542","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0542","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Phong Hi giới thiệu","text":"Phong Hi giới thiệu hai thành viên Thiên Địa Linh Tộc là Độc Giao và Cự Quy với Hàn Lập, cho biết bản lĩnh thần thông của chủng tộc này không yếu hơn yêu tu cấp chín bao nhiêu.","anchor":"hai người bọn hắn xuất thân Thiên địa linh tộc, nếu nói về bản lĩnh thần thông chân chính, tuyệt không yếu hơn ta bao nhiêu"}]},"nguon":["@c0542"]},{"id":"liet-phong-toc","name":"Liệt Phong tộc","cn":"","type":"yeu-toc","typeLabel":"Yêu tộc","diaBan":"","nhanVatChinh":["Phong Hi"],"blurb":"Bộ tộc yêu thú của Phong Hi, thân Linh Cầm có phương pháp tu luyện Phong Hỏa Sí riêng.","detail":"Bộ tộc Liệt Phong Thú, thuộc loài Linh Cầm. Có phương pháp tu luyện Phong Hỏa Sí độc đáo, đôi cánh bản mệnh luyện đến cảnh giới cao nhất có thể dịch chuyển tức thời ngàn dặm. Phong Hi là thành viên cấp chín của tộc, dựa trên phương pháp tu luyện Phong Hỏa Sí để phát triển kế hoạch luyện chế Phong Lôi Sí.","nguonGoc":"","dacDiem":"Thân Linh Cầm, tư chất phong thuộc tính, phương pháp tu luyện Phong Hỏa Sí riêng","thanhVien":[{"ten":"Phong Hi","chucVu":"Thành viên cấp chín","tuChuong":"@c0543","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0543","loai":"nhắc tới","importance":"normal","giaiDoan":"Phong Hi nhắc đến bộ tộc và phương pháp tu luyện","text":"Phong Hi nhắc đến phương pháp tu luyện Phong Hỏa Sí của bộ tộc Liệt Phong Thú là nền tảng cho kế hoạch luyện chế Phong Lôi Sí.","anchor":"kết hợp với phương pháp tu luyện Phong Hỏa Sí của bộ tộc Liệt phong thú chúng ta nên mới có kế hoạch luyện bảo này"}]},"nguon":["@c0543"]},{"id":"giao-long-nhat-toc","name":"Giao Long Nhất tộc","cn":"","type":"yeu-toc","typeLabel":"Yêu tộc","diaBan":"","nhanVatChinh":["Độc Giao"],"blurb":"Tộc Giao Long của Độc Giao, trời sinh thông hiểu thủy thuộc tính. Có yêu tộc cấp cao tham chiến Vạn trượng hải, giúp phá thành trì và giết hai tu sĩ Nguyên Anh kỳ nhân loại.","detail":"Bộ tộc Giao Long, thành viên trời sinh thông hiểu mọi công pháp thủy thuộc tính, chỉ tu luyện sơ qua đã mạnh hơn các chủng tộc khác gấp trăm lần. Có yêu tộc cấp cao tham gia công kích tu sĩ nhân loại ở Vạn trượng hải, nhờ vậy phá được thành trì đối phương và giết hai tu sĩ Nguyên Anh kỳ.","thanhVien":[{"ten":"Độc Giao","chucVu":"Thành viên","tuChuong":"@c0543","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0543","loai":"khai chiến","importance":"normal","giaiDoan":"Tham chiến Vạn trượng hải","trangThaiMoc":"Đang tham chiến","text":"Độc Giao xác nhận Giao Long Nhất tộc có vài yêu tộc cấp cao ra tay công kích tu sĩ nhân loại ở Vạn trượng hải, phá được thành trì đối phương và giết hai tu sĩ Nguyên Anh kỳ.","anchor":"Chính nhờ vậy mà có thể phá được thành trì của đối phương và giết đi hai gã tu sĩ Nguyên Anh Kỳ"}]},"nguon":["@c0543"]},{"id":"toan-nghe-thu-bo-toc","name":"Toan Nghê Thú bộ tộc","cn":"","type":"bo-toc","typeLabel":"Bộ tộc yêu thú","diaBan":"Vạn trượng hải","nhanVatChinh":["Lão Toan Nghê"],"blurb":"Toan Nghê Thú bộ tộc là vương tộc yêu thú lâu đời tại Vạn trượng hải, sở hữu vật truyền thừa Phạm Thánh Chân Phiến ghi chép Tam phạm thánh công. Sau khi một thành viên cấp bảy bị tu sĩ nhân loại giết và thánh vật bị đoạt, Lão Toan Nghê tiêu hao máu huyết phát Vạn yêu lệnh điều mấy vạn yêu thú san bằng đảo nhỏ nhân loại để báo thù.","detail":"Toan Nghê Thú bộ tộc giữ vị trí vương tộc tại Vạn trượng hải, địa vị này gắn liền với việc nắm giữ vật truyền thừa Phạm Thánh Chân Phiến — một thánh vật ghi chép công pháp Tam phạm thánh công. Theo nhận xét của Phong Hi, nếu mất thánh vật này thì bộ tộc khó lòng duy trì vị thế vương tộc, cho thấy nền tảng quyền lực của họ phụ thuộc rất lớn vào bảo vật truyền thừa. Tại mốc @c0544, một thành viên Toan Nghê Thú cấp bảy bị tu sĩ nhân loại giết chết và Phạm Thánh Chân Phiến bị đoạt đi. Lão Toan Nghê trong bộ tộc đã tiêu hao máu huyết bản thân để phát ra Vạn yêu lệnh, hiệu triệu mấy vạn yêu thú san bằng một đảo nhỏ của nhân loại nhằm trả thù.","nguonGoc":"Vương tộc yêu thú lâu đời tại Vạn trượng hải","lanhDaoHienThoi":"Lão Toan Nghê","trangThai":"suy, mất thánh vật","thanhVien":[{"ten":"Lão Toan Nghê","chucVu":"thủ lĩnh","tuChuong":"@c0544","trangThai":"đang hoạt động"},{"ten":"Toan Nghê Thú cấp bảy","chucVu":"thành viên vương tộc","tuChuong":"@c0544","trangThai":"tử vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0544","loai":"khai chiến","importance":"major","giaiDoan":"Phát Vạn yêu lệnh báo thù","trangThaiMoc":"suy, mất thánh vật, phát động chiến tranh","text":"Thành viên Toan Nghê Thú cấp bảy bị tu sĩ nhân loại giết, thánh vật Phạm Thánh Chân Phiến bị lấy. Lão Toan Nghê tiêu hao máu huyết phát Vạn yêu lệnh, mấy vạn yêu thú san bằng đảo nhỏ nhân loại.","anchor":"Toan Nghê Thú bộ tộc chắc chắn không thể nào ngồi yên ở vị trí vương tộc ở Vạn trượng hải"}]},"capNhatToi":"@c0544","nguon":["@c0544"],"uyLuc":"Lão Toan Nghê phát Vạn yêu lệnh điều động mấy vạn yêu thú san bằng một đảo nhỏ nhân loại (@c0544).","dacDiem":"Địa vị vương tộc gắn chặt với vật truyền thừa Phạm Thánh Chân Phiến; mất thánh vật đồng nghĩa nguy cơ mất vị thế vương tộc tại Vạn trượng hải.","congNang":["Phạm Thánh Chân Phiến — vật truyền thừa của bộ tộc, ghi chép công pháp Tam phạm thánh công, là nền tảng để duy trì vị thế vương tộc tại Vạn trượng hải @c0544","Vạn yêu lệnh — lệnh do Lão Toan Nghê tiêu hao máu huyết phát ra, có thể hiệu triệu mấy vạn yêu thú tập hợp tấn công mục tiêu @c0544"]},{"id":"giao-toc","name":"Giao tộc","cn":"蛟族","type":"yeu-toc","typeLabel":"Yêu tộc","diaBan":"Trong biển","nhanVatChinh":["Độc Giao"],"blurb":"Tộc yêu thú Giao long sinh sống trong biển, thế lực hùng mạnh.","detail":"Giao tộc là tộc yêu thú trong biển, Phong Hi đe dọa Hàn Lập rằng nếu giết Độc Giao sẽ bị Giao tộc trong biển đuổi giết cả đời.","thanhVien":[{"ten":"Độc Giao","chucVu":"thành viên","tuChuong":"@c0548","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0548","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc tới như mối đe dọa","text":"Phong Hi dùng Giao tộc làm lá bài đe dọa Hàn Lập, cảnh cáo rằng giết Độc Giao sẽ bị Giao tộc trong biển đuổi giết cả đời.","anchor":"Ngươi muốn từ nay bị Giao tộc trong biển đuổi giết cả đời hả"}]},"nguon":["@c0548"]},{"id":"toc-giao-long","name":"Tộc Giao Long","cn":"","type":"bo-toc","typeLabel":"Bộ tộc yêu thú","diaBan":"Đáy biển vùng phụ cận Ngoại Tinh Hải","nhanVatChinh":["Ly Hỏa Giao","Độc Giao"],"blurb":"Tộc yêu thú dưới đáy biển, tộc trưởng là Ly Hỏa Giao cấp chín trung kỳ. Độc Giao từng là thành viên, bị Hàn Lập giết khiến tộc trưởng nổi giận.","detail":"Tộc Giao Long cư ngụ dưới hơn ngàn trượng đáy nước. Tộc trưởng là yêu thú Ly Hỏa Giao đã tiến hóa tới cấp chín trung kỳ. Khi Hàn Lập giết chết Độc Giao (thành viên của tộc), tộc trưởng nổi giận, tạo thành mối nguy tiềm ẩn cho Hàn Lập.","lanhDaoHienThoi":"Ly Hỏa Giao","nguonGoc":"","quyMo":"Không rõ","caoThuManhNhat":"Ly Hỏa Giao (cấp chín trung kỳ)","trangThai":"hoat-dong","thanhVien":[{"ten":"Ly Hỏa Giao","chucVu":"Tộc trưởng","tuChuong":"@c0551","trangThai":"hoat-dong"},{"ten":"Độc Giao","chucVu":"Thành viên","tuChuong":"","trangThai":"tu-vong"}],"lanhDaoMoc":[{"ten":"Ly Hỏa Giao","tuChuong":"@c0551","denChuong":""}],"tabs":{"tienTrinh":[{"chuong":"@c0551","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ diện","trangThaiMoc":"Tộc trưởng nổi giận vì Độc Giao bị giết","text":"Việc Hàn Lập giết chết Độc Giao khiến Tộc trưởng tộc Giao Long — Ly Hỏa Giao cấp chín trung kỳ — ở dưới hơn ngàn trượng đáy nước nổi giận.","anchor":"việc hắn giết chết Độc Giao lại khiến cho Tộc trưởng tộc Giao Long ở dưới hơn ngàn trượng đáy nước tại vùng biển phụ cận nổi giận"}]},"capNhatToi":"@c0551","nguon":["@c0551"]},{"id":"thai-duong-tong","name":"Thái Dương Tông","cn":"太阳宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Hải vực gần tiểu đảo","nhanVatChinh":["Chiêu sư bá","Tuệ Linh"],"blurb":"Môn phái nhỏ, đệ tử mặc áo lam thống nhất, phong cách cẩn thận không trêu chọc thị phi, nhờ đó tồn tại lâu dài. Có tu sĩ Trúc Cơ kỳ Chiêu sư bá dẫn đầu nhóm đệ tử Luyện Khí kỳ đi lịch lãm.","detail":"Thái Dương Tông có đệ tử mặc áo lam thống nhất. Chiêu sư bá (Trúc Cơ kỳ) dẫn bảy tám thanh niên nam nữ Luyện Khí kỳ cấp bảy tám đi lịch lãm. Chiêu sư bá tự hào rằng Thái Dương Tông tồn tại đến nay nhờ đệ tử làm việc cẩn thận, không manh động trước thị phi.","thanhVien":[{"ten":"Chiêu sư bá","chucVu":"Sư bá (Trúc Cơ kỳ)","tuChuong":"@c0565","trangThai":"hoat-dong"},{"ten":"Tuệ Linh","chucVu":"Đệ tử (Luyện Khí kỳ)","tuChuong":"@c0565","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0565","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhóm đệ tử phát hiện thiên triệu","text":"Bảy tám tu sĩ Thái Dương Tông bay từ hướng Tây Nam đến, dừng cách tiểu đảo hơn mười dặm quan sát thiên triệu. Chiêu sư bá cảnh báo đệ tử không manh động.","anchor":"Thái Dương Tông chúng ta có thể tồn tại đến nay, toàn dựa vào đệ tử môn phái làm việc cẩn thận"}]},"nguon":["@c0565"]},{"id":"than-cuu-duong","name":"Thần Cưu Đường","cn":"神鸠堂","type":"the-luc","typeLabel":"Thế lực","diaBan":"Loạn Tinh Hải","nhanVatChinh":["Ôn Thiên Nhân"],"blurb":"Thế lực của Ôn Thiên Nhân tại Loạn Tinh Hải, hiện đang thiếu vài chấp pháp sứ. Ôn Thiên Nhân nói về Thần Cưu Đường như tổ chức do mình nắm giữ.","detail":"Ôn Thiên Nhân nhắc Thần Cưu Đường hiện tại còn thiếu vài chấp pháp sứ, muốn thu phục tu sĩ trên tiểu đảo làm chấp pháp sứ. Chưa rõ quy mô và cấu trúc cụ thể.","nguonGoc":"","lanhDaoHienThoi":"Ôn Thiên Nhân (suy từ ngữ cảnh)","trangThai":"Đang hoạt động, tuyển mộ chấp pháp sứ","thanhVien":[{"ten":"Ôn Thiên Nhân","chucVu":"Thiếu chủ / Lãnh đạo","tuChuong":"@c0568","trangThai":"dang-hoat-dong"}],"capNhatToi":"@c0568","tabs":{"tienTrinh":[{"chuong":"@c0568","loai":"nhắc tới","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Ôn Thiên Nhân nhắc Thần Cưu Đường còn thiếu vài chấp pháp sứ, muốn thu phục tu sĩ trên đảo.","anchor":"Thần Cưu Đường hiện tại còn thiếu vài tên chấp pháp sứ"},{"chuong":"@c0569","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu nhắc đến","text":"Ôn Thiên Nhân tự xưng thuộc Thần Cưu Đường, ép Hàn Lập quy thuận làm Chấp Pháp Sứ.","anchor":"làm Chấp Pháp Sứ của Thần Cưu Đường ta"}]},"nguon":["@c0568","@c0569"]},{"id":"hoang-minh-dao","name":"Hoàng Minh Đảo","type":"trung-lap","typeLabel":"Đảo trung lập","nhanVatChinh":["Phó đảo chủ Hoàng Minh Đảo"],"blurb":"Đảo nhỏ trung lập ở phụ cận nơi xảy ra sự kiện, Phó đảo chủ là tu sĩ Kết Đan kỳ, không dám trêu chọc Nghịch Tinh Minh.","detail":"Đảo trung lập gần tiểu đảo nơi Hàn Lập và Ôn Thiên Nhân giao chiến. Phó đảo chủ cùng đồng bạn bay đến hỏi thăm tình hình nhưng khi nghe danh Lục Đạo Truyền Nhân liền hoảng sợ rút lui.","nguon":["@c0574"]},{"id":"thon-lac-loan-thach","name":"Thôn lạc trong bãi loạn thạch","cn":"","type":"cong-dong","typeLabel":"Cộng đồng","diaBan":"Bãi loạn thạch đen trong vùng Tuyệt Linh Chi Khí","nhanVatChinh":["Hán tử gầy gò"],"blurb":"Khu định cư của con người trong vùng Tuyệt Linh Chi Khí, có tường đá đen cao hai ba mươi trượng phòng thủ, cổng gỗ lớn với thủ vệ canh gác. Cư dân đã luyện ngoại công, dùng đao kiếm chiến đấu với âm thú.","detail":"Thôn lạc nằm trong bãi loạn thạch đen, được bao bọc bởi tường đá đen cao hai ba mươi trượng, dài hơn ngàn trượng, trên tường có cọc nhọn. Cổng gỗ lớn có mười thủ vệ cầm trường mâu trắng canh gác. Cư dân tuy là người thường nhưng đã luyện ngoại công, dùng đao kiếm chiến đấu với âm thú. Có quy tắc đóng cửa khi mây trời biến đổi và tia chớp lam xuất hiện.","nguonGoc":"Không rõ, cộng đồng người sống sót trong vùng Tuyệt Linh Chi Khí","quyMo":"Thôn lạc có tường thành phòng thủ quy mô","trangThai":"hung","tabs":{"tienTrinh":[{"chuong":"@c0578","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập lần đầu đến thôn","text":"Hàn Lập và Mai Ngưng theo nhóm hán tử gầy gò đến thôn lạc trong bãi loạn thạch đen, được thủ vệ mở cổng cho vào trước khi đóng cửa.","anchor":"Sau mấy tiếng “Oành đùng đùng” thật lớn thì cánh cửa buông xuống để cho bọn họ tiến vào"}]},"nguon":["@c0578"]},{"id":"thon-trang-coi-am-minh","name":"Thôn trang cõi âm minh","cn":"","type":"cong-dong","typeLabel":"Cộng đồng","diaBan":"Cõi âm minh (Vô Danh Chi Địa)","nhanVatChinh":["Lão già mập mạp","Người hai mắt dài"],"blurb":"Thôn trang xây bằng đá đen trong cõi âm minh, có tường thành bao quanh và bãi đá trung tâm với pháp trận sương tím phòng hộ. Quản lý bởi hệ thống trưởng lão, thường xuyên bị âm thú tấn công.","detail":"Thôn trang hoàn toàn xây bằng đá đen thô sơ, có tường thành bao quanh. Giữa thôn là bãi đá cao 30-40 trượng, đỉnh phóng sương tím che bầu trời, hấp thụ sét xanh lam và ngăn âm phong. Có hệ thống trưởng lão quản lý, chừng trăm chiến binh trẻ tuổi phòng thủ có tổ chức, trang bị trường mâu, cung tên, đại thuẫn thô sơ. Năm sáu tu sĩ trong thôn, bao gồm lão già mập mạp (Trúc Cơ). Thực phẩm cực kỳ quý hiếm. Thường xuyên bị âm thú tấn công nhưng phòng thủ trật tự, không ai hỗn loạn.","nguonGoc":"Cộng đồng người bị hút vào cõi âm minh tụ hội lập thôn","lanhDaoHienThoi":"Lão già mập mạp","quyMo":"Khoảng trăm chiến binh và dân cư, 5-6 tu sĩ","trangThai":"Tồn tại, thường xuyên chiến đấu phòng thủ","thanhVien":[{"ten":"Lão già mập mạp","chucVu":"Trưởng lão chính","tuChuong":"@c0579","trangThai":"hoat-dong"},{"ten":"Người hai mắt dài","chucVu":"Trưởng lão, nội lực cao nhất","tuChuong":"@c0579","trangThai":"hoat-dong"},{"ten":"Hán tử gầy gò","chucVu":"Thành viên","tuChuong":"@c0579","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0579","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập và Mai Ngưng gia nhập thôn","trangThaiMoc":"Tồn tại, đang phòng thủ chống âm thú","text":"Hàn Lập và Mai Ngưng được dẫn vào thôn, gặp trưởng lão. Thôn bị Giảo Tranh Thú tấn công, pháp trận sương tím kích hoạt trói chân thú, chiến binh phản kích bằng giáo tên.","anchor":"Hai vị mời ngồi. Một khi đã đến đây, mọi người đều cùng một tộc, tất nhiên sẽ hết sức giúp đỡ"}]},"nguon":["@c0579"]},{"id":"thon-nhan-loai-am-minh","name":"Thôn nhân loại trong Âm Minh","cn":"","type":"thon-lac","typeLabel":"Thôn lạc","diaBan":"Âm Minh chi địa","nhanVatChinh":["Lão già mập mạp"],"blurb":"Hệ thống bảy tám thôn nhân loại phân bố khắp Âm Minh chi địa, sống bằng trồng trọt hạn chế và đánh bắt tôm cá. Người vô dụng bị đuổi ra ngoài tự sinh tự diệt.","detail":"Nhân loại bị hút vào không gian xé rách Âm Minh chi địa, mất khả năng dùng pháp thuật, phải dựa vào thể phách sinh tồn. Phân bố bảy tám thôn, thực vật cực kỳ thiếu thốn, chỉ vài nơi trồng trọt được. Phần lớn âm thú mang độc không ăn được, thực phẩm chủ yếu từ tôm cá khi Tuyệt Linh Chi Khí phun ra. Quy luật sinh tồn khắc nghiệt: người không đóng góp được sẽ bị đuổi ra ngoài thôn.","nguonGoc":"Nhân loại bị hút vào không gian xé rách","quyMo":"Bảy tám thôn phân bố khắp Âm Minh","lanhDaoHienThoi":"Đại trưởng lão (Lão già mập mạp)","trangThai":"Tồn tại gian nan","tabs":{"tienTrinh":[{"chuong":"@c0580","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ hệ thống thôn lạc","text":"Đại trưởng lão giải thích nhân loại phân bố bảy tám thôn khắp Âm Minh, thực phẩm thiếu thốn, người vô dụng bị đuổi ra ngoài tự sinh tự diệt.","anchor":"cũng có bảy ,tám chỗ phân bố khắp âm minh"}]},"nguon":["@c0580"]},{"id":"dai-tan-hoang-trieu","name":"Đại Tấn hoàng triều","cn":"大晋皇朝","aliases":["Đại Tấn quốc","Tấn quốc"],"type":"de-quoc","typeLabel":"Đế quốc","diaBan":"Chưa rõ vị trí cụ thể trong hải vực, có Loan Nam Châu là tiểu đảo thuộc quyền","nhanVatChinh":["Lão già mập mạp"],"blurb":"Siêu cấp đế quốc được mệnh danh là thánh địa tu sĩ trần gian, nơi tu tiên giới hưng thịnh nhất không nơi nào sánh bằng.","detail":"Lão giả hình dáng lão nông tự hào giới thiệu Đại Tấn hoàng triều là thánh địa tu tiên, tu tiên giới cực kỳ hưng thịnh, quy mô vượt xa mọi nơi. Hàn Lập đã nghe về quốc gia này khi còn ở Thiên Nam và động lòng muốn đến thăm. Loan Nam Châu là một tiểu đảo thuộc Đại Tấn, quê hương lão giả.","nguonGoc":"Siêu cấp đế quốc đã tồn tại lâu đời, được biết đến khắp tu tiên giới","quyMo":"Siêu cấp đế quốc","trangThai":"hung","capNhatToi":"@c0581","tabs":{"tienTrinh":[{"chuong":"@c0581","loai":"nhac-toi","importance":"normal","giaiDoan":"Được lão giả giới thiệu trong Âm Minh giới","text":"Lão giả hình dáng lão nông tiết lộ bản thân đến từ Đại Tấn hoàng triều Loan Nam Châu, tự hào ca ngợi Đại Tấn là thánh địa tu sĩ trần gian hưng thịnh nhất. Hàn Lập đã nghe tên từ Thiên Nam, động lòng muốn đến.","anchor":"gọi Đại Tấn quốc chúng ta là này một thánh địa của tu sĩ trần gian cũng không quá"}]},"nguon":["@c0581"]},{"id":"ngu-long-hai-the-luc","name":"Ngũ Long Hải","cn":"五龙海","type":"khu-vuc","typeLabel":"Khu vực / Thế lực","diaBan":"Ngũ Long Hải","nhanVatChinh":["Bão Hoàn Tử"],"blurb":"Vùng biển nơi Bão Hoàn Tử xuất thân, còn có tông môn biết chế tác thạch phù/ngọc phù cổ xưa — loại phù chú đã gần thất truyền ở nơi khác.","detail":"Theo Bão Hoàn Tử, chỉ một ít tông môn trong Ngũ Long Hải còn có người chế tác loại thạch phù/ngọc phù cổ xưa này. Bão Hoàn Tử là tu sĩ xuất thân từ đây, hiện bị khốn trong Âm Minh giới.","tabs":{"tienTrinh":[{"chuong":"@c0582","loai":"nhắc tới","importance":"normal","giaiDoan":"Bão Hoàn Tử nhắc đến","text":"Bão Hoàn Tử nhắc Ngũ Long Hải là nơi duy nhất còn bảo tồn kỹ thuật thạch phù/ngọc phù cổ xưa.","anchor":"cũng chỉ có một ít tông môn trong Ngũ Long Hải chúng ta còn có người chế tác loại phù chú cổ xưa này"}]},"nguon":["@c0582"]},{"id":"linh-phu-mon","name":"Linh Phù Môn","cn":"灵符门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Đại Tấn quốc","nhanVatChinh":["Vân đạo hữu"],"blurb":"Môn phái tại Đại Tấn quốc, Vân đạo hữu là thành viên.","detail":"Linh Phù Môn là một môn phái thuộc Đại Tấn quốc. Vân đạo hữu, tu sĩ mặt đỏ râu bạc trắng, thuộc về môn phái này, hiện bị kẹt trong thôn ở Âm Minh giới.","nguon":["@c0586"]},{"id":"hong-tho-thon","name":"Hồng Thổ thôn","cn":"","type":"thon-lac","typeLabel":"Thôn lạc","diaBan":"Vùng âm minh","nhanVatChinh":["Tráng hán Hồng Thổ thôn"],"blurb":"Thôn nhỏ trong vùng âm minh, quy mô hơn trăm người, có tường bảo vệ bốn phía nhưng thấp và nhiều chỗ bị phá không sửa.","detail":"Thôn lạc của cư dân sống trong vùng âm minh. Tường bao bốn phía chỉ cao bảy tám trượng, nhiều chỗ bị phá không tu sửa. Khi khe mở ra, thôn dân phát hiện xương trắng của người bên ngoài bị âm thú giết, đã chôn di hài và thu đồ vật vào kho.","nguon":["@c0589"]}]};
